INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('e4eea46b-0872-4098-b0ec-da12ffeb1ece', 'HyperPNL', 'The first decentralized prop trading protocol built on Hyperliquid, enabling traders to compete in onchain challenges and earn performance-based rewards.', 'HyperPNL is a decentralized proprietary trading protocol that reimagines the traditional prop trading firm model by executing everything fully onchain using smart contracts on the Hyperliquid ecosystem. Traders pay a fee to enter evaluation challenges, complete two-phase trading assessments under strict risk rules (5% daily loss max, 10% total loss max), and upon passing, receive real capital from a Treasury Pool to trade with — all without intermediaries or trust assumptions. The protocol also offers a yield layer for liquidity providers who can contribute capital to the Treasury Pool and earn real yield from challenge fees and trader performance. HyperPNL differentiates itself from traditional prop firms through instant, smart-contract-driven funding decisions, automatic payouts, and full transparency. The project originated from the Hyperliquid Community Hackathon and is currently in a pre-launch/coming-soon phase. The team is small (approximately 4 employees).', 'Crypto / Web3', 'Infrastructure', 'Pre-seed', NULL, 'HyperPNL competes in the crypto prop trading space but differentiates through its fully onchain, decentralized approach. Traditional/centralized crypto prop firms include FTMO (founded 2015, forex-first with crypto expansion), Crypto Fund Trader (est. 2022, crypto-focused via Bybit). Unlike these centralized competitors, HyperPNL uses smart contracts for challenge evaluation, funding, and payouts — removing trust assumptions and intermediary delays. Its positioning as the first decentralized prop trading protocol on Hyperliquid targets crypto-native traders seeking transparency and permissionless access.', 'https://hyperpnl.com/', 'discovered', '{DeFi,"Prop Trading",Hyperliquid,"Smart Contracts","Decentralized Finance"}', NULL, '2026-03-20 09:34:21.62821', 'https://hyperpnl.com/', NULL, 'https://x.com/hyperpnl', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
