INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('3876a3ca-4691-45e3-a146-84592b79b099', 'Stripe', 'Stripe builds economic infrastructure for the internet, providing APIs and tools for online payment processing and commerce.', 'Stripe is a financial infrastructure platform that enables businesses of all sizes to accept payments, manage revenue, and accelerate business growth online. Founded in 2010 by Irish brothers Patrick and John Collison, the company provides a suite of APIs and tools that allow developers to integrate payment processing into websites and mobile applications with minimal effort. Stripe handles billions of dollars in transactions annually for millions of businesses worldwide, from startups to Fortune 500 companies like Amazon, Google, and Shopify.

Beyond core payment processing, Stripe has expanded into a comprehensive financial platform offering products including Stripe Connect (marketplace payments), Stripe Atlas (business incorporation), Stripe Capital (business lending), Stripe Treasury (banking-as-a-service), Stripe Billing (subscription management), Stripe Radar (fraud prevention), Stripe Tax (automated tax compliance), Stripe Issuing (card creation), and Stripe Climate (carbon removal). The company has become one of the most valuable private technology companies in the world.

Stripe''s significance lies in its role as critical infrastructure powering the digital economy. By dramatically simplifying the complexity of online payments and financial services, Stripe has lowered barriers to entry for internet businesses globally. The company operates in over 45 countries and supports hundreds of payment methods, positioning itself as the default payments backbone for the modern internet economy.', 'Fintech', 'API / Platform', 'Growth', 'Stripe has raised approximately $9.4 billion in total funding across multiple rounds. Key rounds include: Seed round in 2010-2011 from Y Combinator, Peter Thiel, and Elon Musk; Series A (~$18M, 2012) led by Sequoia Capital; Series B ($80M, 2014) led by Founders Fund; Series C ($150M, 2016, ~$9B valuation) with General Catalyst, CapitalG; Series D ($245M, 2018, $20B valuation) with Tiger Global; Series E ($250M, 2019, $35B valuation) with Andreessen Horowitz, General Catalyst, Sequoia; Series G ($600M, 2020, $36B valuation); Series H ($600M, March 2021, $95B valuation) with Sequoia, Fidelity, Andreessen Horowitz, Baillie Gifford, and others; Series I ($6.5B, March 2023, $50B valuation) with Andreessen Horowitz, Baillie Gifford, Founders Fund, General Catalyst, Goldman Sachs, Temasek, and others. By 2024-2025, the company''s secondary market valuation rose significantly, reportedly reaching $91.5 billion or higher in secondary share sales in early 2025. Notable investors include Sequoia Capital, Andreessen Horowitz, General Catalyst, Tiger Global, Founders Fund, Fidelity, Baillie Gifford, CapitalG (Alphabet), Goldman Sachs, Temasek, and GIC.', '1. **Adyen** - Netherlands-based public company offering end-to-end payment processing for large enterprises; differentiates with a single-platform approach but Stripe is more developer-friendly and startup-oriented. 2. **PayPal / Braintree** - PayPal''s Braintree competes directly in developer payment APIs; Stripe differentiates with superior developer experience, broader product suite, and faster innovation. 3. **Square (Block)** - Focuses more on in-person/SMB payments with growing online presence; Stripe differentiates by focusing primarily on internet-native businesses and providing more extensive APIs. 4. **Checkout.com** - UK-based payment processor competing for enterprise clients; Stripe differentiates with its broader ecosystem of financial products beyond payments. 5. **Worldpay / FIS** - Legacy payment processors serving large enterprises; Stripe differentiates with modern API-first architecture, developer tools, and agility in product development.', '', 'discovered', '{Payments,"Developer Tools","Financial Infrastructure",B2B,"API Platform"}', NULL, '2026-03-04 12:08:32.972403', NULL, NULL, NULL, NULL, '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('a21e42fd-647e-4be2-a9fe-5ef31806ec97', 'Delphi Digital', 'Independent research, consulting, and venture firm providing institutional-grade analysis on the digital asset and crypto market.', 'Delphi Digital is a research-driven firm founded in 2018 that provides institutional-grade analysis, consulting, and investment services for the digital asset market. The company operates as a cooperative coalition of independently owned entities under the Delphi brand, including Delphi Research (founded 2018), Delphi Ventures, and Delphi Labs (established 2021 as a protocol R&D arm, later launching an accelerator program in 2023). Their research subscription product offers actionable insights on crypto markets, DeFi, tokenomics, gaming, and macro trends, serving top-tier investors, institutional teams, and builders.

The founding team — Anil Lulla, Medio Demarco, Kevin Kelly, Tom Shaughnessy, and Yan Liberman — previously worked at institutions like Deutsche Bank, Bloomberg, and Oppenheimer before transitioning to crypto. The firm has built a strong reputation through deep-dive reports that have been cited by notable industry figures including Ethereum co-founder Vitalik Buterin. Delphi Ventures operates as a venture capital arm that has made investments across the crypto ecosystem. The company has no external investors in its core research business, giving it independence in decision-making. Delphi Labs raised $13.5M in 2023 from P2P (creator of Lido) and Jump Crypto for its Web3 accelerator program. The company is headquartered in Miami Beach, FL with a fully remote team.', 'Crypto / Web3', 'Other', 'Seed', 'Delphi Labs raised $13.5M in April 2023, led by P2P (creator of Lido) with participation from Jump Crypto. The funding was for their Web3 accelerator program. The raise was Delphi''s first time courting outside investments. The core Delphi Digital research business has operated without external investors, being self-funded by the founding team.', 'Delphi Digital competes in the institutional crypto research and analytics space. Direct competitors include Messari (crypto data analytics and research platform), Nansen (blockchain analytics), The Block (crypto media and research), Blockworks (crypto media and research), Coin Metrics (crypto data), Dune Analytics (blockchain data platform), and Kaiko (crypto market data). Delphi differentiates through its integrated research + consulting + ventures model, deep-dive reports with actionable trading insights, exclusive community access, and strong reputation for tokenomics advisory. Unlike pure data platforms, Delphi combines qualitative research with macro analysis and has deep protocol-level consulting relationships.', 'https://x.com/ashwathbk', 'discovered', '{"Crypto Research","Digital Assets",Tokenomics,DeFi,"Web3 Consulting"}', NULL, '2026-03-06 07:12:42.072316', 'https://delphidigital.io', '', 'https://x.com/Delphi_Digital', 'https://www.linkedin.com/company/delphi-digital', '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('d847ed3e-e67f-44a7-9c65-5d8dd5c34b0d', 'Freeport Markets', 'AI-powered tradable news feed that turns social media signals into actionable trades across crypto, stocks, and pre-IPO equities via a self-custodial DeFi interface.', 'Freeport Markets is building an internet-native investing platform that translates real-time social media and news signals into executable trade ideas. The platform uses AI analysts to track breaking news across Twitter, financial media, and social platforms, distilling what matters into actionable trade cards with evidence and context. Users can follow trusted investors, analysts, and publications, and the AI filters noise to surface only trading-relevant signals across 400+ stocks, crypto assets, and pre-IPO names like SpaceX, OpenAI, Anthropic, and Anduril.

The platform operates on a self-custodial model where assets stay in the user''s wallet with no rehypothecation or lock-ins. Freeport integrates multiple DeFi protocols into one interface, offering cross-chain swaps, yield opportunities, lending, staking, and diversified portfolio construction using a quantitative factor-based framework. The company applies a rigorous screening methodology to vet assets for legitimacy and liquidity, and routes trades to minimize slippage and MEV.

Founded in 2025 and backed by Y Combinator (F25 batch) and Alliance DAO, the team of 3 is based in New York. They launched their mobile app (iOS and Android) in early 2026 and are expanding into perpetual DEX integrations, prediction markets, and deeper DeFi protocol coverage.', 'Crypto / Web3', 'API / Platform', 'Pre-seed', 'Pre-Seed round raised on August 1, 2025. Investors: Y Combinator and Alliance DAO. Exact amount undisclosed.', 'Freeport competes at the intersection of DeFi aggregation and social/narrative-driven trading. Key competitors include: Zerion (non-custodial wallet and portfolio app with DeFi discovery across chains), Zapper (portfolio tracking and DeFi discovery with execution across protocols), and Coinbase/Robinhood (centralized crypto platforms Freeport positions against on fees and yield). Freeport differentiates by combining AI-driven social media signal processing with DeFi execution — turning narrative and attention data into tradable strategies. The addition of pre-IPO equities and tokenized stocks alongside crypto is a further differentiator.', 'https://x.com/freeportmrkts?s=21&t=nNmmq43RV9J-8fLg3xTwXA', 'reaching_out', '{DeFi,"AI Trading","Social Trading",Pre-IPO,Self-Custody}', NULL, '2026-03-20 09:34:17.851333', 'https://freeportmarkets.com', NULL, 'https://x.com/freeportmrkts', 'https://www.linkedin.com/company/freeportmarkets', '1e9bf641-c93c-4629-906a-f50db9050164', 'DeFi Aggregator / Social Trading', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('534dfb28-6662-44b4-99dc-e4a5f280463b', 'Legend Trade', 'A gamified, social crypto trading arena with real-time matchmaking, copy trading, and trader reputation/ELO systems — incubated by GTE.', 'Legend Trade (legend.trade) is building the world''s first ''Trader vs. Trader'' arena, framing crypto trading as a multiplayer competitive experience. The platform allows users to get matchmade in real-time against other traders, discover top performers through rich media content, track their performance, and copy trade them directly. Incubated by GTE (The Global Token Exchange), a Paradigm-backed decentralized trading platform built on MegaETH, Legend Trade layers social and competitive mechanics on top of derivatives trading infrastructure. Features include competitive trading with social graph integration, reputation/ELO ranking systems, and a live community of traders. The product is currently coming out of stealth. Legend Trade raised a $1.5M pre-seed round on October 16, 2025 from notable crypto-native funds including Figment Capital, Big Brain Holdings, Bodhi Ventures, GTE, Kosmos Ventures, MitonC, and several angel investors. The platform positions itself at the intersection of social trading, gamification, and DeFi derivatives.', 'Crypto / Web3', 'API / Platform', 'Pre-seed', 'Pre-Seed (October 16, 2025): $1.5M raised from Figment Capital, Big Brain Holdings, Bodhi Ventures, GTE, Kosmos Ventures, MitonC, and angel investors.', 'Legend Trade occupies a niche at the intersection of gamified competitive trading, social trading, and DeFi derivatives. Traditional copy trading features exist on centralized exchanges like Bybit, Bitget, OKX, and BingX. Decentralized social trading platforms are nascent. Conceptual competitors include perp DEXs with social layers like Hyperliquid, copy trading protocols like dHEDGE, and CEX copy trading (Bybit, Bitget, eToro). Legend differentiates through its arena/matchmaking mechanic, ELO-style reputation system, and integration with GTE''s DEX infrastructure.', 'https://x.com/legendtrade', 'discovered', '{"Social Trading","Gamified Trading","Copy Trading","DeFi Derivatives","GTE Ecosystem"}', NULL, '2026-03-20 09:34:25.493262', 'https://legend.trade', NULL, 'https://x.com/legendtrade', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', 'Perpetuals/Derivatives', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('0ba6a757-40e2-47d3-88cf-702b82a46aa4', 'Figma', 'A collaborative, browser-based design platform for building user interfaces and prototypes.', 'Figma is a cloud-based design and prototyping tool that enables teams to collaborate in real-time on user interface design, prototyping, and design systems. Unlike traditional desktop-based design tools, Figma runs entirely in the browser, making it accessible across platforms and enabling multiple designers, developers, and stakeholders to work simultaneously on the same file. The platform includes Figma Design for UI/UX design, FigJam for collaborative whiteboarding, and Figma Slides for presentations, along with a robust developer handoff experience.

Figma has become the dominant design tool in the product design industry, effectively displacing Adobe''s suite (particularly Sketch and Adobe XD) for UI/UX workflows. Its multiplayer editing capabilities, component libraries, design tokens, and extensive plugin ecosystem have made it the standard tool for product teams at companies ranging from startups to Fortune 500 enterprises. The company has also been expanding into adjacent areas like AI-powered design features, variable support for design tokens, and Dev Mode for improved designer-developer collaboration.

Figma famously was the target of a $20 billion acquisition attempt by Adobe in September 2022, which was ultimately abandoned in December 2023 due to regulatory concerns from the European Commission and UK''s Competition and Markets Authority. The failed acquisition underscored Figma''s dominant market position and competitive threat to Adobe. Figma continues to operate independently and has been investing heavily in AI features and expanding its product suite.', 'Enterprise SaaS', 'SaaS', 'Growth', 'Figma has raised approximately $330 million in total funding across multiple rounds. Key rounds include: Seed round (2013) from Index Ventures and others; Series A (~$14M, 2015) led by Greylock Partners; Series B (~$25M, 2018) led by Kleiner Perkins; Series C (~$40M, 2019) led by Sequoia Capital; Series D (~$50M, 2020) led by Andreessen Horowitz at a $2B valuation; Series E ($200M, 2021) led by multiple investors at a $10B valuation. Notable investors include Index Ventures, Greylock Partners, Kleiner Perkins, Sequoia Capital, Andreessen Horowitz (a16z), and Dylan Field''s angel investors. The company was valued at approximately $12.5 billion in a secondary share sale in 2024.', '1. **Sketch** - Mac-native UI design tool that was the industry leader before Figma; lacks real-time collaboration and browser-based access, which led to its decline in market share. 2. **Adobe XD** - Adobe''s attempt to compete in the UI design space; was effectively discontinued after the failed Figma acquisition. 3. **Canva** - A broader design platform targeting non-designers and marketers; competes in adjacent spaces like presentations and simpler design tasks. 4. **Framer** - A design-to-code platform that competes particularly in prototyping and website building with more advanced interaction capabilities. 5. **Penpot** - An open-source design and prototyping platform that appeals to teams seeking self-hosted or open-source alternatives. Figma differentiates through its real-time multiplayer collaboration, browser-based accessibility, dominant market share creating network effects, extensive plugin ecosystem, and deep integration with developer workflows.', '', 'discovered', '{"Design Tools",Collaboration,B2B,"Product Design","Developer Tools"}', NULL, '2026-03-04 12:09:49.507565', NULL, NULL, NULL, NULL, '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('55f1c4fd-c689-488c-9706-74ecba121ab9', 'Astra Markets', 'AI-powered trading and market intelligence platform for financial markets', 'Astra Markets is a fintech company focused on leveraging artificial intelligence and advanced analytics to provide market intelligence, trading insights, and financial data solutions. The platform appears to serve traders and financial professionals with tools to better navigate and analyze financial markets.

The company operates at the intersection of AI and finance, providing data-driven market analysis and potentially automated trading capabilities. By combining machine learning with financial market data, Astra Markets aims to democratize access to sophisticated trading intelligence that was traditionally available only to institutional players.

As financial markets become increasingly data-driven and algorithmic, companies like Astra Markets are positioning themselves to capture the growing demand for AI-enhanced financial tools among both retail and professional traders.', 'Fintech', 'API / Platform', 'Seed', '', 'Astra Markets competes in the AI-driven financial analytics and trading intelligence space. Comparable companies include: 1) Alpaca - provides API-based trading infrastructure and market data; 2) Kavout - AI-powered investment analytics platform; 3) Numerai - crowdsourced hedge fund using AI/ML models; 4) QuantConnect - algorithmic trading platform with cloud-based backtesting; 5) Composer - automated trading strategies platform. Astra Markets differentiates through its specific approach to AI-driven market intelligence and its focus on making institutional-grade analytics more accessible.', 'https://x.com/Astra_Markets', 'discovered', '{"AI Trading","Market Intelligence","Financial Analytics",Fintech}', NULL, '2026-03-04 12:12:35.529777', NULL, NULL, NULL, NULL, '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('cda62790-cb76-4573-9997-009a560f3929', 'Sequence Markets', 'The execution layer for digital assets — smarter and faster trade execution across fragmented crypto venues.', 'Sequence Markets builds execution technology for digital-asset markets. Their platform improves trade routing across venues and helps institutions and active investors access better pricing, lower slippage, and more reliable execution. They operate as a fully non-custodial technology provider and integrate with existing brokers, exchanges, and custodial platforms.

The company addresses the critical problem of liquidity fragmentation in crypto markets — digital asset liquidity is spread across hundreds of centralized (CEX) and decentralized (DEX) venues, forcing teams into manual venue-by-venue workflows with zero visibility into execution quality, resulting in inconsistent fills and hidden slippage.

Founded in 2026 and backed by Y Combinator (W26 batch), Sequence Markets is headquartered in New York, NY with a team of 5 employees. Their website claims access to $15B+ in liquidity, and they position themselves at the intersection of institutional crypto trading and the rapidly growing tokenized asset market.', 'Crypto / Web3', 'Infrastructure', 'Seed', 'Y Combinator Winter 2026 batch. No other funding rounds publicly confirmed.', 'Sequence Markets operates in the digital asset execution and smart order routing space. Key competitors include: Talos (institutional crypto trading infrastructure), CoinRoutes (smart order routing for crypto), and FalconX (institutional crypto prime brokerage, though FalconX operates a principal trading/prime brokerage model which differs from Sequence Markets'' non-custodial execution technology approach). Sequence Markets differentiates with its non-custodial architecture and unified CEX+DEX liquidity sourcing in a single workflow.', 'https://sequencemkts.com/', 'discovered', '{"crypto execution","digital assets","trade infrastructure","tokenized assets","smart order routing"}', NULL, '2026-03-06 06:56:41.968642', 'https://sequencemkts.com/', '', '', 'https://www.linkedin.com/company/sequence-markets', '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('1afbd370-5e53-479c-a9db-83496e5a7e05', 'Astra Technologies', 'Quantitative cryptocurrency trading firm building unified API infrastructure for crypto markets.', 'Astra Technologies is a San Francisco-based quantitative cryptocurrency trading firm founded in 2023. The company trades a wide variety of digital assets and derivatives across every major trading venue, offering both trading services and OTC liquidity aggregation across venues for optimal execution. Their unified API (astra-api.dev) provides crypto trading infrastructure.

Founded by Aditya (Adi) Baradwaj, a former Alameda Research software engineer who later spoke publicly about the firm''s failures and testified as a witness at the SBF fraud trial, the company is built on deep firsthand experience with the failures of crypto trading infrastructure at scale. Baradwaj''s background — having witnessed security and engineering failures at Alameda that cost at least $190 million according to his public disclosures — informs Astra''s mission to build reliable, secure crypto trading infrastructure.

The company operates with a small team (2-10 employees) and positions itself as building ''the fastest and most reliable crypto trading infrastructure on the planet.''', 'Crypto / Web3', 'API / Platform', '', '', 'Astra competes in the crypto trading infrastructure and liquidity aggregation space. Key competitors include: (1) Talos — institutional crypto trading infrastructure platform; (2) Falconx — crypto trading platform for institutional investors; (3) Wintermute — algorithmic crypto market maker and OTC trading; (4) CoinRoutes — smart order routing for crypto markets; (5) Paradigm — institutional crypto trading network. Astra differentiates through its unified API approach that aggregates liquidity across venues and provides a developer-friendly interface, combined with the founder''s deep experience building trading systems at Alameda Research and engineering background from Google.', 'https://x.com/adi_baradwaj', 'discovered', '{"crypto trading","trading infrastructure",API,"OTC liquidity","quantitative trading"}', NULL, '2026-03-04 12:53:47.248587', NULL, NULL, NULL, NULL, '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('db3343bc-f929-4600-bf39-cd85d2951f0f', 'Peanut Trade', 'MEV market maker providing full-cycle TGE management and fair market making for crypto projects.', 'Peanut Trade is a blockchain trading company founded in 2020 that specializes in crypto market making, Token Generation Event (TGE) management, and MEV (Miner Extractable Value) trading strategies. Originally developed by Remme, a blockchain-based authentication/PKI company, Peanut pivoted to become a profit-sharing market maker deploying HFT, CEX/DEX MEV strategies, arbitrage, and futures-with-spots strategies across 20 blockchains including Solana, Base, and Tron.

The company offers three core services: Fair Launch (protecting DEX token launches from sniping bots via white-label anti-bot solutions), a DEX Market Maker Platform (enabling custom trading strategies using mempool scanning and MEV techniques), and cross-exchange delta-neutral arbitrage. Peanut Trade reports having supported 1,000+ token launches, works with 80+ B2B clients, and has processed 500B+ API requests for cross-chain market making. The company is integrated with exchanges including Binance, OKX, and Coinbase.

Headquartered in Lisbon, Portugal (with registration in the British Virgin Islands), Peanut Trade has approximately 60-70 employees. The company has its own utility token (NUX) on Ethereum and operates as both a services company and a proprietary trading fund.', 'Crypto / Web3', 'Services', 'Seed', 'Seed round (date unconfirmed per Crunchbase). Earlier in late 2020 to early 2021, Peanut raised approximately $7.96M total across multiple token sale rounds: a $1M presale (Dec 2020), a $5.5M public token sale (Feb 2021), and an IEO on Gate.io (per ICO Drops). Investors include AVstar Capital, Evangelion Capital, and Primeblock Ventures (per PitchBook). The predecessor company Remme had an ICO with a $20M hard cap in Feb-Mar 2018, but the actual amount raised is unverified.', 'Peanut Trade competes in the crypto market making space against established players including Wintermute, DWF Labs, GSR Markets, Amber Group, and Keyrock. Smaller/mid-tier competitors include Yellow Capital and Gotbit. Peanut differentiates through its ''fair market making'' model with profit-sharing, its focus on DEX-native MEV strategies, Fair Launch anti-bot protection, and rapid multi-chain integration. Unlike traditional market makers, Peanut positions itself as a full-cycle TGE partner rather than purely a liquidity provider.', 'https://x.com/Denis_0x', 'discovered', '{"Market Making",MEV,DeFi,"Token Launch",HFT}', NULL, '2026-03-04 13:24:16.001956', 'https://peanut.trade', 'https://github.com/peanut-trade', 'https://x.com/PeanutTrade', 'https://www.linkedin.com/company/peanut-trade', '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('dacf8668-f148-4902-97b9-5ffcaefc457a', 'Fermi Labs', 'Building crypto''s most performant central limit order book (CLOB) DEX on Solana with instant finality and fair ordering.', 'Fermi Labs is a Web3 research and development studio focused on building next-generation decentralized exchange infrastructure on the Solana blockchain. Their flagship product, Fermi DEX, leverages a capital-efficient order book architecture that separates deposit requirements from order placement, enabling market makers to post orders without locking collateral through match-time liquidity provision mechanisms. The platform supports configurable settlement periods and integrates with liquidity aggregators to enhance trading efficiency.

Beyond Fermi DEX, the company is also developing Continuum, a sequencing layer focused on fair transaction ordering. Founded in 2023 and headquartered in Weston, Florida, Fermi Labs positions itself as building the infrastructure layer for on-chain capital markets. The company has published research on blockchain capital markets roadmaps, exploring how blockchains can achieve NASDAQ-like market microstructure without trusted intermediaries.', 'Crypto / Web3', 'Infrastructure', 'Pre-seed', '$1.2M Pre-Seed round announced May 21, 2025, led by Equilibrium and Big Brain Holdings. Additional investors include Solana Foundation, Nom, FarmerJoe, Robert Chen, MacBrennan, alexbond, Ashwath, Gaius, and mhonkasalo (per ICO Drops). PitchBook lists Delphi Ventures and Bonk as investors, though these could not be independently cross-verified.', 'Fermi Labs competes in the Solana DEX and on-chain orderbook space. Key competitors include: Phoenix (instant settlement on-chain orderbook on Solana), OpenBook (community-led CLOB fork of Serum v3), Drift Protocol (decentralized exchange on Solana), Raydium (AMM with central order book integration), and Jupiter (leading DEX aggregator on Solana). Fermi differentiates through its capital-efficient order book architecture that doesn''t require collateral locking for order placement, match-time liquidity provision, and its complementary Continuum sequencing layer for fair transaction ordering. The Continuum product is thematically related to shared/decentralized sequencing solutions like Espresso Systems and Astria, though no direct competitive comparison has been confirmed by the company.', 'https://x.com/FermiLabs', 'discovered', '{DeFi,Solana,"Orderbook DEX","On-chain Capital Markets","Decentralized Exchange"}', NULL, '2026-03-06 07:16:55.326138', 'https://fermilabs.xyz', '', 'https://x.com/FermiLabs', '', '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('7b376c2e-4c39-4ddb-83f8-768d0d8ad203', '3F Labs', 'DeFi''s Global Yield Network — a one-click leverage solution for real-world assets (RWAs) on-chain.', '3F Labs is building a DeFi protocol that bridges top-tier alternative assets with decentralized finance, delivering leveraged yield, transparency, and global access — all on-chain. The platform enables users and institutions to participate in global yield markets backed by real-world and digital assets, providing composable financial primitives for sustainable on-chain yield generation.

3F operates at the intersection of tokenized RWAs and DeFi lending infrastructure. The protocol enables institutional-grade arbitrage strategies to be brought fully on-chain, with adjustable leverage via bridge loans. It has deployed a 3F x Steakhouse USDC vault on Morpho that lends against a curated set of institutional-grade real-world assets.

Founded by DeFi veterans from Steakhouse Financial and Abraxas Capital Management, 3F is backed by an angel round featuring prominent DeFi figures including Rune Christensen (MakerDAO/Sky founder), Sam MacPherson, DeFi Dad, Ivangbi, Michael Ippolito, and others. The company is positioning itself as the next generation of rates markets infrastructure in DeFi.', 'Crypto / Web3', 'Infrastructure', 'Pre-seed', 'Angel round (November 2025). Investors include Rune Christensen, Sam MacPherson, DeFi Dad, Ivangbi, Michael Ippolito, Ernest Oppetit, Michael Bentley, Jason Yanowitz, Curved Ventures, Steakhouse Financial, BraveNewDeFi, Daedalus Angel Syndicate, Tyson Wynne, Anthony Leutenegger, Rob Montgomery, Lyuben Belov, and others.', '3F operates in the growing intersection of DeFi yield infrastructure and RWA tokenization. Competitors and adjacent players include: (1) Ondo Finance — tokenized securities/treasury products; (2) Maple Finance — institutional DeFi lending with RWA collateral; (3) Centrifuge — RWA tokenization and DeFi lending; (4) Ethena — yield-bearing synthetic dollar; (5) Pendle — yield tokenization and trading. 3F differentiates through its one-click leverage solution specifically designed for RWAs, its Morpho-based vault infrastructure via Steakhouse curation, and its deep ties to the MakerDAO/Sky ecosystem and institutional-grade fund managers like Abraxas Capital.', 'https://x.com/3f_xyz', 'researching', '{DeFi,RWA,Yield,Leverage,"Institutional DeFi"}', NULL, '2026-03-20 09:34:01.942328', 'https://3f.xyz', NULL, 'https://x.com/3FLabs', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', 'RWA', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('084ae8fd-fe6f-4878-afec-857f488cf36f', 'Dreamcash', 'A mobile-first, self-custodial trading app built on Hyperliquid offering perpetual futures on crypto, equities, and commodities with up to 40x leverage.', 'Dreamcash is a decentralized, self-custodial mobile trading platform built on Hyperliquid''s high-performance Layer-1 blockchain. It provides a CEX-like user experience — intuitive mobile UI, fiat on-ramps, and streamlined onboarding — while preserving on-chain settlement, transparency, and full self-custody. Users can trade crypto perpetual futures, spot tokens, and real-world asset (RWA) perpetuals including S&P 500, Tesla, Nvidia, gold, and silver, all collateralized with USDT0 (Tether''s omnichain stablecoin via LayerZero).

The platform operates under the entity Supreme Liquid Labs and is affiliated with the Beam Foundation, the team behind the Merit Circle DAO and Beam gaming ecosystem. Dreamcash leveraged Hyperliquid''s HIP-3 permissionless standard to deploy 10 RWA perpetual markets without needing Hyperliquid Foundation approval, meeting the 500,000 HYPE staking requirement. Tether made an undisclosed strategic investment in Supreme Liquid Labs in February 2026 to back USDT0-collateralized markets on the platform, along with a $200,000 weekly trading incentive program. Selini Capital serves as the liquidity provider for the 10 RWA markets.

Dreamcash has surpassed 100,000 waitlist signups and approximately 140,000 app downloads. The platform claims over 1,500 active traders. It is available on iOS, Android, web, and desktop. The platform runs a Season-based points/XP program (Season One launched February 18, 2026) with community expectations of a future CASH token airdrop.', 'Crypto / Web3', 'Infrastructure', NULL, 'Strategic investment from Tether (February 2026, undisclosed amount) into parent entity Supreme Liquid Labs. Investment supports a $200,000 weekly trading incentive program for CASH/HIP-3 markets. Affiliated with and supported by the Beam Foundation. No publicly disclosed priced round with specific dollar amounts.', 'Dreamcash competes in the Hyperliquid frontend/interface ecosystem and the broader decentralized perpetuals space. Direct competitors include Hyperliquid''s native interface (app.hyperliquid.xyz), Aster (a perp DEX on BNB Chain that has recorded up to $36B in 24-hour volume), and Lighter (a zk-rollup perp DEX on Arbitrum). Broader competitors include centralized exchanges with mobile perps (Binance, Bybit, OKX) and other decentralized perp platforms (dYdX, GMX). Dreamcash differentiates through mobile-first UX, USDT0 collateral (vs. Hyperliquid''s native USDC), RWA perpetuals (stocks, commodities), self-custody, no-KYC onboarding, and AI-powered trading insights.', 'https://x.com/Dreamcash', 'discovered', '{DeFi,"Perpetual Futures",Hyperliquid,"Mobile Trading",RWA}', NULL, '2026-03-20 09:34:10.01636', 'https://dreamcash.xyz', NULL, 'https://x.com/Dreamcash', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', 'Perpetuals/Derivatives', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('3d49234e-2717-4407-ac7c-7f062f22bc96', 'Fireplace', 'The Bloomberg Terminal for prediction markets — a professional trading terminal aggregating markets, liquidity, and execution across prediction market venues.', 'Fireplace is a Hong Kong-based startup building institutional-grade trading infrastructure for prediction markets. The platform serves as a unified terminal that aggregates markets, liquidity, and execution across prediction market venues like Polymarket and Kalshi, delivering real-time data, advanced charting, wallet/whale/insider tracking, and market discovery tools. Its wallet technology and automations are powered by its in-house Enclave Money infrastructure.

As prediction markets fragment across platforms, blockchains, and regulatory regimes, Fireplace is positioning itself as the cross-venue aggregation layer with smart order routing — automatically routing orders to the best-priced and deepest liquidity pool when the same market exists across multiple venues. The platform uses chain abstraction technology in collaboration with Socket Protocol to make aggregation seamless across crypto and regulated venues. Features include personalized feeds, 1-tap trades, advanced order types, and auto-resolving markets.

In its first five months, Fireplace has demonstrated strong early traction with 30,000+ traders on its waitlist, over 10,000 organic followers on X, an official Polymarket badge, and a public launch on January 27, 2026. The company offers both a mobile app and a web-based pro terminal (pro.fireplace.gg).', 'Crypto / Web3', 'Infrastructure', 'Pre-seed', 'Pre-seed: $1.5M raised in February 2026, led by Frachtis, with participation from White Star Capital and several other VCs and angel investors, including syndicate rounds on Legion and Echo.', 'Fireplace sits in the prediction market infrastructure layer rather than competing directly with prediction market platforms themselves. The underlying platforms it aggregates include Polymarket (backed by ICE/NYSE parent at ~$8B valuation) and Kalshi ($11B valuation after $1B Series E). Direct competitors in the aggregation/terminal layer are nascent — the prediction market infrastructure space is very early. Flutter Entertainment (FanDuel parent) is investing $200-300M into prediction markets in 2026 but as a platform, not an aggregation layer.', 'https://pro.fireplace.gg/', 'discovered', '{"Trading Infrastructure",DeFi,"Cross-venue Aggregation","Crypto / Web3"}', NULL, '2026-03-20 09:34:13.826162', 'https://fireplace.gg', NULL, 'https://x.com/fireplacegg', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('f8b303b0-f5be-4420-9a69-b497897a7350', 'Mirage Protocol', 'A decentralized liquidity layer on Move (Aptos/Movement) powered by mUSD, a yield-bearing synthetic stablecoin, fueling a high-performance perpetual futures exchange.', 'Mirage Protocol is building modular money on Move-based ecosystems, starting with Aptos and Movement. At its core, Mirage is a composable liquidity layer that leverages synthetic assets to power a wide range of financial products. The team has built a high-performance perpetual futures DEX (Mirage Market) that offers trading across crypto, commodities, and currencies with up to 100x leverage. Liquidity is sourced through mUSD, an overcollateralized yield-bearing stablecoin minted against high-quality collateral like USDC or APT, where deposited collateral acts as counterparty to traders and minters earn a share of trading fees.

Mirage''s Synthetic Liquidity Model differentiates from multi-asset liquidity pool approaches (like GMX) by allowing LPs to more effectively manage risk and asset exposure. The protocol''s modular architecture enables other teams to build on top of Mirage liquidity, with options and prediction market protocols reported in development. Built by a small team of software developers with deep experience in on- and off-chain trading systems at institutional trading firms, Mirage is positioned as an early native perps DEX in the Move ecosystem.

The protocol is live on Aptos mainnet and has received backing from notable crypto-native investors including Robot Ventures, Selini Capital, and Mohammad Shaikh (Aptos co-founder). The team is also engaged in Aptos governance, having co-authored the AIP-119 proposal to reduce staking rewards.', 'Crypto / Web3', 'Infrastructure', 'Seed', 'Seed round: $1.6M raised in May 2025. Investors: Robot Ventures, Selini Capital, Ambush Capital, Native Crypto, Echo, Mohammad Shaikh (Aptos co-founder), Norbert Bodziony.', 'In the broader perps DEX space, Mirage competes with Hyperliquid (dominant market leader by volume), GMX (Arbitrum), dYdX (Cosmos appchain), Jupiter Perps (Solana), Drift (Solana), Lighter, and Aster (BNB Chain). Within the Aptos/Move ecosystem specifically, the primary competitor is Decibel (Aptos Labs-incubated perps DEX that launched on mainnet in Feb 2026). Merkle Trade, a former Aptos-based perps DEX that processed ~$30B cumulative volume, shut down in Feb 2026. Mirage differentiates through its synthetic liquidity model (mUSD as composable stablecoin margin vs. traditional LP pools) and its modular design allowing third parties to build financial products on Mirage liquidity.', 'https://x.com/moonshiesty?s=21', 'discovered', '{DeFi,"Perpetual Futures",Aptos,Move,"Synthetic Assets"}', NULL, '2026-03-20 09:34:33.119977', 'https://mirage.money', 'https://github.com/mirage-protocol', 'https://x.com/mirage_protocol', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', 'Perpetuals/Derivatives', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('cf7b4843-c645-4e2e-a206-b674f04a08ec', 'Nous Research', 'Open-source AI research lab building world-class language models and decentralized training infrastructure on Solana.', 'Nous Research is a decentralized AI startup that develops open-source, human-centric language models and builds infrastructure for distributed AI training. Founded in 2023 as a company (originating from a volunteer collective of AI researchers who met on Discord and social media around 2022), the company has evolved into one of the most prominent open-source AI labs, releasing popular model families like Hermes (fine-tuned from Meta''s Llama series) and developing novel architectures and training methods. Their models are designed to be steerable and uncensored, offering an alternative to the restrictive outputs of commercial AI systems.

The company''s core technical contribution is DeMo (Decoupled Momentum Optimization), which reduces inter-GPU communication bandwidth by up to 10,000x during pre-training, enabling large-scale model training across geographically distributed hardware connected over standard internet connections. This technology, branded as DisTrO (Distributed Training Over-the-Internet), powers their Psyche Network, a decentralized training platform built on Solana that allows anyone to contribute idle computing power for AI training, incentivized through blockchain-based token rewards. Nous is also developing Atropos, an open-source reinforcement learning framework.

With a $1 billion token valuation after their Series A, Nous Research occupies a unique position at the intersection of open-source AI and crypto/blockchain. The ~20-person team has shipped numerous models including Hermes 3, Hermes 4, and the Consilience 40B-parameter model, and has collaborated with Diederik Kingma (co-inventor of the Adam optimizer and OpenAI founding team member) on the DeMo paper. Their approach represents a bet that decentralized, community-driven AI training can compete with the centralized approach of hyperscaler labs.', 'AI / ML', 'Infrastructure', 'Series A', 'Seed 1 (Jan 2024): $5.2M co-led by Distributed Global and OSS Capital, with participation from Vipul Ved Reddy (Together AI CEO), Balaji Srinivasan, Alex Atallah (OpenRouter/OpenSea), Sahil Chaudhary (Glaive AI), Gavin Uberti (Etched AI), and others. Additional seed funding of ~$15M (including a previously unannounced June 2024 round) from Together AI, Delphi Ventures, North Island Ventures, and Solana co-founder Raj Gokal, bringing total seed to ~$20M. Also received a grant from Andreessen Horowitz. Series A (Apr 25, 2025): $50M led by Paradigm at $1B token valuation. Total raised: ~$70M.', 'Nous Research competes broadly with both closed-source AI labs (OpenAI, Anthropic, Google DeepMind) and other open-source model builders (Meta AI/Llama, Mistral AI, DeepSeek). In the decentralized AI training space, competitors include projects like Gensyn, Together AI (which is also an investor), and Bittensor ecosystem projects. In the crypto-AI infrastructure space, competitors include Render Network and other DePIN projects. Nous differentiates through its combination of competitive model quality (Hermes series), proprietary distributed training technology (DeMo/DisTrO/Psyche), and a strong community-driven ethos.', 'https://x.com/teknium?s=21&t=nNmmq43RV9J-8fLg3xTwXA', 'discovered', '{"Open Source AI","Decentralized Training",LLMs,"Crypto AI",DePIN}', NULL, '2026-03-20 09:34:36.972718', 'https://nousresearch.com', 'https://github.com/NousResearch', 'https://x.com/NousResearch', 'https://www.linkedin.com/company/nousresearch', '1e9bf641-c93c-4629-906a-f50db9050164', 'Open Source LLMs / Decentralized AI Training', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('b23b7510-8dab-4e54-8c8f-2f302cb9cd73', 'PUMPCADE', 'A Solana-based project building interactive blockchain experiences that can be embedded into chat environments, powered by the $PUMPCADE token.', 'PUMPCADE is an early-stage crypto project on Solana. Its website tagline is ''Speculate on anything, anywhere there''s a chat box,'' and its X/Twitter bio describes it as ''Building the rails to power the intersection of blockchain and interactive experiences.'' Third-party sources describe it as enabling arcade mini-games inside live chat environments. The $PUMPCADE token was launched via Pump.fun and trades on PumpSwap. The team behind the project is anonymous, with no publicly identified founders. The website (pumpca.de) and X account (@pumpcade, joined October 2025) provide minimal detail about the product, technology stack, or roadmap.', 'Crypto / Web3', NULL, NULL, NULL, 'PUMPCADE operates in the broader Solana ecosystem of tokens launched via Pump.fun. If building interactive chat-based gaming experiences, it would sit alongside Telegram-based trading bots and other chat-integrated crypto projects. Specific competitors are unverified.', 'https://x.com/pumpcade?s=21&t=nNmmq43RV9J-8fLg3xTwXA', 'discovered', '{Solana,"Chat Integration","Interactive Gaming",Pump.fun}', NULL, '2026-03-20 09:34:40.799964', 'https://pumpca.de', NULL, 'https://x.com/pumpcade', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('87465d6c-d80c-4803-ab52-40a7c9a93f4f', 'Propr', 'A crypto-native, transparent proprietary trading firm built on Hyperliquid, offering traders funded accounts to trade 270+ perpetual contracts across crypto, equities, and FX.', 'Propr is a crypto-native proprietary trading firm that provides traders with funded accounts to trade perpetual contracts on Hyperliquid. The platform differentiates itself through full on-chain transparency — every trade, position, and payout is verifiable on-chain — combined with trader-friendly rules including no consistency requirements, no profit caps, no time limits, and profit splits ranging from 80% to 90%. Propr supports 270+ assets spanning crypto perps (BTC, ETH), equity perps (AAPL, TSLA, SPX), and FX perps, all accessible from a custom-built trading terminal with real-time news feeds, advanced charting, and order book depth.

Propr is built by XBorg, a startup studio previously known for creating the largest fan engagement platform in esports (working with Team Liquid, Evil Geniuses, and Team BDS). XBorg is a spin-off of SwissBorg, one of Europe''s largest crypto wealth platforms with 900K+ users and $1.5B+ in assets under management. Propr has its own token ($PROPR) with a planned TGE. XBG token stakers receive 13% of the $PROPR supply airdropped at TGE.

Additional products in the ecosystem include trading tools like TWAP Detector and Market Magnet. XBorg describes prop trading as a $20B+ market ripe for disruption through transparency and better UX.', 'Crypto / Web3', 'Other', 'Seed', 'Parent company XBorg previously raised a $5M seed round ($2M community + $3M VCs) in July 2023 and raised a total of $9M via a token sale in June 2024. XBorg is a spin-off of SwissBorg.', 'Propr competes in the crypto prop trading space against firms like FTMO (established Prague-based prop firm), HyroTrader (crypto-focused prop firm), Breakout (acquired by Kraken in September 2025), Crypto Fund Trader, FundedNext, and Bitfunded. Propr differentiates through: (1) on-chain execution and transparency via Hyperliquid rather than centralized brokers or CFDs, (2) a broader instrument universe (270+ perps including equities and FX alongside crypto), (3) no hidden rules with a public rule changelog, (4) on-chain payouts, and (5) a native token ($PROPR) creating community alignment. Most competitors use centralized platforms like MetaTrader and lack on-chain verifiability.', 'https://x.com/proprxyz', 'discovered', '{DeFi,"Prop Trading",Hyperliquid,"On-chain Trading","Crypto Trading"}', NULL, '2026-03-20 09:34:48.674846', 'https://propr.xyz', NULL, 'https://x.com/ProprXYZ', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('fb6399f8-1fec-460c-8efb-dad986aa255e', 'Stratium', 'Institutional-grade structured finance products (volatility perps, asset baskets, yield strategies) built natively on Hyperliquid via HIP-3.', 'Stratium is building the global strategy layer for onchain finance, bringing institutional-grade structured products to DeFi through Hyperliquid''s HIP-3 infrastructure. The platform deploys complex derivatives products across four verticals: volatility markets, FX/macro derivatives, data-backed assets, and real-world asset products — all as perpetual markets with continuous liquidity.

The protocol''s first live product is a HYPE liquid staking vault, where users deposit HYPE and receive srHYPE, a transferable liquid staking token that earns validator rewards and trading fee share while retaining liquidity. Stratium is working toward integrations that let srHYPE function as productive collateral across HyperEVM — including lending markets, liquidity provision in DEX pools, and use as a building block in structured yield strategies. The staking vault smart contracts were audited by Halborn (December 2025), and the development was done by HorizonX (horizonx-tech). Mainnet launch for the structured markets is expected Q1 2026.

Stratium''s partners include Native Markets (USDH stablecoin), SEDA, Across, BlockScholes, Halborn (security audits), Pyth Network, G-20 Group, and Adaptive Frontier. The project has a points system rewarding early participation through vault activity, and is part of the broader HIP-3 ecosystem on Hyperliquid that includes 20+ projects building permissionless perpetual markets.', 'Crypto / Web3', 'Infrastructure', NULL, NULL, 'Stratium operates in the Hyperliquid HIP-3 ecosystem, competing with other structured product and derivative deployers. Key competitors include: Volmex (bringing crypto volatility indices like BVIV/EVIV to HIP-3, directly competing on volatility perps), Nunchi (yield-targeted perpetual swaps and basis perpetuals), Felix Protocol (modular leverage protocol with vaults and structured products on Hyperliquid), Ventuals (pre-IPO equity perps), and TradeXYZ/Unit (tokenized equity perps like XYZ100). In liquid staking for HYPE specifically, Stratium''s srHYPE competes with Kinetiq''s kHYPE (dominant HYPE LST) and Hyperbeat''s beHYPE (built in collaboration with Ether.fi). Stratium''s differentiation lies in combining liquid staking with structured finance products (volatility perps + asset baskets) in a single protocol, whereas competitors tend to focus on one vertical.', 'https://stratium.xyz/', 'discovered', '{DeFi,"Structured Products",Hyperliquid,HIP-3,"Liquid Staking"}', NULL, '2026-03-20 09:34:52.547185', 'https://stratium.xyz', 'https://github.com/horizonx-tech/stratium-hyperliquid-vault', 'https://x.com/StratiumX', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', 'Perpetuals/Derivatives', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('cdf4c888-8980-4d71-8b04-a4ac408dcabf', 'Supernova (ParRate)', 'The first millisecond-latency, fully onchain order book exchange for trading and hedging interest rates, FX, and crypto cross-rates.', 'Supernova is building ParRate, a composable engine for discovering, hedging, and trading the cost of capital onchain. The platform enables fixed-rate borrowing and lending from existing money markets like Aave and Morpho through capital-efficient rates trading, requiring less than 1.5% of the principal size to go long or short on interest rates. It provides continuous rate discovery, a unified yield curve aggregating data from all underlying money markets, and real-time settlement.

The protocol addresses a massive TradFi market — interest rate swaps are the world''s second-largest financial derivatives market — yet this remains a nascent, blue-ocean opportunity in DeFi. Supernova''s approach differs from yield tokenization protocols by offering a proper order book exchange with millisecond latency, enabling institutional-grade rate trading 24/7 with full transparency. The product is currently in private beta.', 'Crypto / Web3', 'Infrastructure', 'Pre-seed', 'Reported to be backed by YZi Labs (formerly Binance Labs), though the investment does not appear in publicly available portfolio databases. Specific funding amount not publicly confirmed.', 'The onchain interest rate derivatives space is still nascent. Key competitors include: (1) Pendle Finance — the dominant yield tokenization protocol, enabling trading of yield-bearing asset components via a custom AMM, but focused on yield tokenization rather than direct rate trading; (2) IPOR Labs — a leading interest rate swap protocol in DeFi, providing an interest rate index and derivatives for fixed-rate lending, based in Zug, Switzerland; (3) DELV (formerly Element Finance) — building decentralized fixed-income protocols including the Hyperdrive AMM; (4) Notional Finance — focused on fixed-rate lending and borrowing on Ethereum. Supernova differentiates through its order book model (vs AMM), millisecond latency, capital efficiency (<1.5% of principal), and focus on rate trading as a standalone primitive rather than embedded in yield tokenization.', 'https://x.com/supernovalabs_?s=21&t=nNmmq43RV9J-8fLg3xTwXA', 'reaching_out', '{"Interest Rate Derivatives",DeFi,"Onchain Order Book","Fixed Rate Lending"}', NULL, '2026-03-20 09:35:00.173705', 'https://www.supernova.vision/', NULL, 'https://x.com/SupernovaLabs_', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', 'Perpetuals/Derivatives', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('059dc521-995e-4dd9-91b5-edb1b8614c2d', 'Tare', 'A fintech startup designed to save the consumer lending industry billions of dollars wasted on excess fees.', 'Tare (tare.io) is a pre-launch fintech company focused on eliminating excess fees in the consumer lending industry. The company is currently in stealth/pre-launch mode with a landing page collecting sign-ups. Tare Inc. was originally incorporated in 2023 in New York and previously operated as an AI email marketing platform (tare.ai) co-founded by Eileen Dai and Max Sidebotham, which was acquired by Skio. The current tare.io consumer lending venture appears to represent a new direction under the same corporate entity, though the current leadership team has not been publicly disclosed.', 'Fintech', 'Other', NULL, 'Tare has received investment from OpenSky Ventures and Pear VC (California), according to PitchBook. Specific round amounts and dates are not publicly confirmed.', 'Without a launched product, the exact competitive positioning is unclear. The broader fintech lending market is projected to grow at a 27.4% CAGR to nearly $5 trillion by 2030.', 'https://x.com/tare_io', 'discovered', '{Fintech,"Consumer Lending",Pre-launch}', NULL, '2026-03-20 09:35:04.076614', 'https://tare.io', NULL, NULL, 'https://www.linkedin.com/company/tare-ai', '1e9bf641-c93c-4629-906a-f50db9050164', 'Lending', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('f363f359-7428-471d-8f12-31ad7c78bdd4', 'Strobe Labs', 'Building infrastructure for permissionless, trust-minimized markets and decentralized derivatives (including perp.city for perpetual futures).', 'Strobe Labs is a crypto infrastructure company working to enable new kinds of trust-minimized markets. The company believes that human intermediaries in the loop prevent blockchains from reaching their full potential, and that more resilient systems of the future will rely on better ways to verify data and computation. Their vision is to power applications and markets that couldn''t exist before — allowing users to build, exchange, and interact without permission or trust.

Strobe is also the team behind perp.city, a product related to perpetual futures and decentralized derivatives trading. The company is co-founded by Nitesh Gupta (CEO) and Nirel Gershwind, and is based in New York. Nitesh Gupta previously worked at Magna, Carta, Vise, and Bloomberg, and is a Tufts University alumnus. Nirel Gershwind brings experience from CosMove, Mira Finance, Lockheed Martin, and the National Science Foundation, with a background from the University of Maryland.

The company is backed by Latent Capital (listed as a 2023 DeFi investment in their portfolio). Strobe Labs currently employs approximately 5 people and appears to be at an early stage of development.', 'Crypto / Web3', 'Infrastructure', 'Pre-seed', 'Backed by Latent Capital (listed as a 2023 DeFi investment on latentcap.com). No confirmed public funding round amounts available. Note: not to be confused with the separate event-marketing Strobe Labs in San Francisco, which was acquired by TicketWeb in August 2017.', 'Operates in the decentralized derivatives and permissionless markets infrastructure space. Given its focus on trust-minimized verification infrastructure, competitors may include both infrastructure-layer projects and decentralized derivatives protocols such as Hyperliquid, dYdX, GMX, Synthetix, and Drift Protocol. Strobe differentiates by focusing on verification infrastructure and enabling new market types, rather than operating as a pure trading venue. Note: the exact competitive positioning depends on which layer of the stack Strobe primarily targets.', 'https://www.linkedin.com/in/niteshvgupta', 'in_diligence', '{DeFi,"Crypto Infrastructure","Perpetual Futures","Permissionless Markets","Trust-Minimized Systems"}', NULL, '2026-03-20 09:34:56.309458', 'https://strobe.org/', NULL, NULL, 'https://www.linkedin.com/company/strobelabs', '1e9bf641-c93c-4629-906a-f50db9050164', NULL, 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('38d9978a-a8ed-4d34-8874-608a79b213ee', 'WeLikeSports', 'A social platform for onchain sports pools — brackets, survivor pools, squares, and pick''em — built on Monad, making it easy to compete with friends with no rake, no commissioner, and instant payouts.', 'WeLikeSports is a social platform for sports pools and games that brings the classic experience of March Madness brackets, survivor pools, squares, and pick''em contests onchain via the Monad blockchain. The platform eliminates traditional pain points like commissioner management, rakes, and delayed payouts by leveraging blockchain-based smart contracts for transparent, trustless settlement.

The product is positioned at the intersection of social sports gaming and crypto, targeting the casual sports pool market with a modern, gamified experience. WeLikeSports is currently in early-stage launch, with a focus on college campus GTM strategies and building out game formats around major sporting events like March Madness and NFL football season. The team is based in NYC and is actively hiring growth interns for campus expansion.', 'Crypto / Web3', 'Consumer', 'Pre-seed', NULL, 'WeLikeSports occupies a unique niche at the intersection of social sports pools and crypto/onchain settlement. Key competitors and adjacent players include: (1) ESPN/Yahoo/CBS bracket pools — traditional Web2 incumbents with massive reach but no onchain settlement or instant payouts; (2) Polymarket — the dominant onchain prediction market but focused on binary outcomes, not social pool formats; (3) Levr Bet — a leveraged sports betting platform built on Monad; (4) BettorEdge — peer-to-peer sports betting marketplace with social features; (5) Football.Fun — onchain fantasy sports on Base; (6) Azuro — onchain sports betting infrastructure layer. WeLikeSports differentiates by focusing specifically on the social, friend-group pool experience (brackets, survivor, squares) rather than individual betting/prediction markets, with no rake and instant settlement.', 'https://x.com/playWLS', 'discovered', '{"Sports Pools","Monad Ecosystem","Social Gaming","Onchain Consumer"}', NULL, '2026-03-20 09:35:08.057146', 'https://welikesports.com', NULL, 'https://x.com/PlayWLS', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', 'Social Sports Gaming', 0, 8, 'The founder seems to have a deep passion to do this and has been a founder 3-4 times previously as well. He seems like he wants it. It is also at touching on that zone of "financial entertainment" too. ', NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('b42d2a15-8eeb-4bcd-95f2-d920edfb373b', 'PredictParity (Parity)', 'Cross-platform prediction market aggregator enabling users to trade, track top traders, and analyze market data across multiple prediction market platforms.', 'PredictParity, branded as Parity, is building a cross-platform prediction market aggregator that allows users to trade prediction markets across multiple venues (such as Polymarket and Kalshi), track top traders, analyze market data, and make more informed trading decisions. The platform positions itself as a unifying layer for the rapidly growing prediction markets space.

The company is in a very early pre-launch phase — its Twitter account (@PredictParity) was created in September 2025 with ~2,860 followers but has not yet posted content. The founder, known as ''MovieTime'' (@MovieTimeDev), is an active voice in the prediction markets community, sharing analysis on prediction market accuracy, arbitrage opportunities between platforms like Polymarket and Kalshi, and market dynamics. The company explicitly states ''NO COIN'' on its Twitter profile, distancing itself from any associated tokens.

The prediction market industry has seen significant growth, with major platforms like Kalshi and Polymarket raising at multi-billion dollar valuations. Parity appears to be positioning itself in the aggregator/tooling layer of this ecosystem.', 'Crypto / Web3', 'API / Platform', 'Pre-seed', NULL, 'The prediction market aggregator/tooling space is nascent but increasingly crowded. Direct competitors in the aggregation layer include: Polynance (prediction market aggregator with SDK), pmxt (open-source SDK for Polymarket/Kalshi/Limitless, self-described as ''CCXT for prediction markets''), Oddpool (cross-venue odds aggregation and analytics, described as ''the Bloomberg for prediction markets''), TradeFox (professional prediction market aggregator and prime brokerage backed by Alliance DAO and CMT Digital), Forcazt (AI-powered prediction market analytics and aggregator), and PolyRouter (data aggregation in open beta). The major prediction market platforms — Polymarket (crypto-native, $3.7B+ election volume) and Kalshi (CFTC-regulated, $11B valuation as of December 2025) — are the primary venues Parity would aggregate across. Opinion ($20M pre-Series A from Hack VC/Jump Crypto) is another growing prediction market platform. Differentiation is unclear at this stage given the pre-launch status.', 'https://x.com/movietimedev?s=21&t=nNmmq43RV9J-8fLg3xTwXA', 'in_diligence', '{"prediction markets","market aggregator","cross-platform trading",Polymarket,Kalshi}', NULL, '2026-03-20 09:34:44.734407', 'https://predictparity.com', NULL, 'https://x.com/PredictParity', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', 'Prediction Markets', 2, 8, 'The Founder (Movietimedevv) seems like he has a strong technical understanding of the prediction market ecosystem and is essentially building a UX layer on top of different pred. mkts, aided by intelligence from AI. ', NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('1b06af05-1b8d-4312-8cd4-b0de8fad4245', 'Covenant AI (Templar)', 'Decentralized AI training infrastructure on Bittensor, enabling permissionless, incentivized pre-training, post-training, and compute provisioning for large language models.', 'Covenant AI is building an end-to-end decentralized AI training stack on the Bittensor blockchain, consisting of three interconnected platforms (called ''orders''): Templar (Subnet 3) for permissionless decentralized pre-training of large language models, Basilica (Subnet 39) for decentralized GPU compute provisioning, and Grail (Subnet 81) for reinforcement learning-based post-training. What started as the Templar project has expanded into the broader Covenant AI ecosystem under the motto ''One Covenant, Many Orders.''

The team has trained Covenant72B — a 72-billion-parameter model on 1.2+ trillion tokens using fully permissionless, decentralized infrastructure — claimed to be the largest model ever trained in a decentralized setting. They have published two key research papers accepted at a NeurIPS workshop (OPT2025): Gauntlet (a blockchain-compatible reward mechanism for distributed training) and SparseLoCo (a communication-efficient optimizer that combines top-k sparsification with 2-bit quantization, achieving 1-3% gradient communication). Their system has demonstrated approximately 6% communication overhead.

Covenant AI is transitioning from pure research to a research-plus-product model, with training/fine-tuning APIs and enterprise sales in motion. The project operates on the Bittensor network where miners contribute compute and earn TAO token rewards proportional to their verified contributions to model improvement. The team is currently developing ''Templar: Crusades,'' a competition system for optimized training code implementations.', 'Crypto / Web3', 'Open Source', NULL, 'No confirmed traditional VC funding rounds. The project operates on Bittensor''s token-based incentive system (TAO emissions). Revenue model is transitioning toward paid pre-training services with plans for 100% of training fees to buy back Covenant tokens.', 'Covenant AI competes in the decentralized AI training space against several projects: Prime Intellect (raised $70.4M total including $15M led by Founders Fund, trained INTELLECT-3 106B MoE model, though that run used centralized GPUs), Nous Research ($50M Series A led by Paradigm at $1B token valuation, building decentralized training on Solana), Gensyn (verifiable training computation), and Pluralis.ai (SWARM parallelism approaches). Additionally, Bittensor-native competitors like IOTA subnet pursue similar decentralized training goals. Covenant differentiates through being the only fully permissionless, live production system for decentralized training at scale on Bittensor, with novel algorithms (SparseLoCo, Gauntlet) and a vertically integrated stack covering pre-training, compute, and post-training.', 'https://x.com/tplr_ai', 'discovered', '{"Decentralized AI","Distributed Training",Bittensor,"LLM Pre-training","Open Source AI"}', NULL, '2026-03-20 09:34:06.13532', 'https://tplr.ai', 'https://github.com/tplr-ai', 'https://x.com/tplr_ai', NULL, '1e9bf641-c93c-4629-906a-f50db9050164', 'Decentralized AI Infrastructure', 0, 9, 'Ran a 72B param training run in a decentralized manner, with commodity internet. Runs 3 subnets on bittensor with liquid tokens. ~150m combined mcap of subnet tokens. SN3 is most interesting. ', NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('1856f2b2-f134-4455-9a94-d8ae2f4a1f41', 'Splits Protocols, Inc.', 'Financial infrastructure for onchain teams — audited, open-source smart contracts for splitting, distributing, and managing onchain payments across EVM chains.', 'Splits Protocols (branded as Splits, formerly 0xSplits) builds the financial infrastructure layer for onchain teams. Their core product is a set of audited, open-source, non-upgradeable smart contracts that enable trustless, composable, gas-efficient splitting and distribution of ETH and ERC20 tokens. The protocol charges zero fees on every transaction. Key contract primitives include Split (percentage-based revenue distribution), Waterfall (sequential/tiered payouts for expense recoupment), Swapper (automatic token conversion), and Liquid Splits (NFT-represented transferable ownership). The protocol has been integrated into major web3 platforms including SuperRare, 1stDibs, Sound, Zora, Art Blocks, and Arpeggi Labs, and powers Protocol Guild''s distribution of donations to Ethereum core developers.

More recently, Splits has expanded from payment primitives into a full-stack financial operations platform with ''Teams'' — a multichain multisig system with passkey-based access control for managing team funds and onchain operations via smart contract wallets. Teams offers crosschain multi-signature accounts with professional workflows for treasury management. The company provides a comprehensive developer toolkit including SDK, subgraph, prebuilt UI components (SplitsKit), and API, positioning itself as both protocol infrastructure and an application layer for onchain business operations.

Headquartered in San Francisco, Splits operates as permanent public infrastructure — the core contracts charge zero fees and are designed to run forever without dependencies. The company appears to be exploring monetization through its Teams product, which offers a more full-featured experience for onchain organizations.', 'Crypto / Web3', 'Open Source', '', 'The company is private and based in San Francisco. Crunchbase lists funding milestones but specific amounts, dates, and investors are not publicly confirmed.', 'Splits operates in the onchain payments and treasury management space. Key competitors and adjacent protocols include: (1) Superfluid — real-time token streaming protocol focused on continuous money flows and recurring payments; (2) Sablier — time-locked token streaming for vesting and grant disbursements; (3) LlamaPay — lightweight multi-chain streaming protocol focused on DAO payroll; (4) Gnosis Safe / Safe — the dominant multi-sig treasury management tool that Splits'' Teams product competes with; (5) Coinshift — DAO treasury management platform. Splits differentiates through its composable, zero-fee, non-upgradeable contract architecture that serves as permanent infrastructure (''hyperstructure''). While competitors focus primarily on streaming/vesting, Splits uniquely addresses percentage-based income splitting and tiered waterfall distributions.', 'https://x.com/0xSplits', 'discovered', '{"Onchain Payments","Treasury Management","Smart Contracts","Ethereum Infrastructure","Open Source"}', NULL, '2026-03-20 14:43:15.002332', 'https://splits.org', 'https://github.com/0xSplits', 'https://x.com/0xSplits', '', '1e9bf641-c93c-4629-906a-f50db9050164', 'Payments', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('c093f41d-ae81-45dd-98f5-94641ff1a725', 'Pods Finance (Deframe by Pods)', 'API infrastructure that enables neobanks, wallets, and exchanges to integrate DeFi yield, cross-chain swaps, and crypto-backed loans into their platforms with minimal development effort.', 'Pods Finance, now operating as Deframe by Pods, is a Brazilian-founded DeFi infrastructure company that started in 2020 as a decentralized non-custodial options protocol on Ethereum. The company originally built an Options AMM allowing users to create, buy, and sell options on-chain, along with structured products like the stETH Volatility Vault (stETHvv). The company has pivoted to a B2B API/infrastructure play under the Deframe brand, providing a unified, non-custodial API and embeddable widget that enables custodians, wallets, exchanges, fintechs, and banks to integrate DeFi functionalities — including swaps, crypto-backed loans, savings/yield accounts, and lending/borrowing — directly into their own applications. Deframe''s architecture interfaces with on-chain protocols trustlessly, and the platform also offers a KYC-compliant lending pool option for regulated platforms. Based in São Paulo, Brazil, Pods has raised $12.1M across multiple rounds and has been part of the FENASBAC Next 2023 acceleration program, partnering with Núclea and Mercado Bitcoin. The company also contributed to Brazil''s DREX (digital real) initiative using the Starlight ZK-privacy solution, an open-source tool originally developed by Ernst & Young. Their current go-to-market focuses on serving neobanks in Latin America and globally, offering embedded DeFi capabilities.', 'Crypto / Web3', 'API / Platform', 'Seed', 'Pre-Seed (August 2020): $800K — investors include Boost VC, Framework Ventures, P2P Capital, BitScale, Zeeprime, The LAO. Seed (December 2022): $5.6M — investors include IOSG Ventures, Tomahawk VC, Republic, Framework Ventures, 4RC. Additional investors across rounds include Alexia Ventures, Arche Fund, Cyber.Fund, Daedalus Angels, Hash#CIB, and others (22 investors total per PitchBook). Total raised: ~$12.1M per PitchBook (may include undisclosed rounds beyond the two confirmed, which sum to $6.4M).', 'Deframe competes in the DeFi-as-a-Service / embedded DeFi API space. Potential competitors include Blockdaemon/expand.network (unified DeFi API for institutions), Zerion (DeFi portfolio and transaction APIs), and Fireblocks (institutional DeFi access via MPC wallets). Deframe''s differentiation lies in its non-custodial, trustless architecture, deep specialization in structured products and yield strategies from its DeFi-native origins, strong LatAm market positioning with partnerships in the Brazilian financial ecosystem (Núclea, Mercado Bitcoin, DREX initiative), and both API and embeddable widget integration options.', 'https://x.com/PodsFinance', 'discovered', '{"DeFi Infrastructure","Embedded Finance","API Platform","LatAm Fintech","Neobank Infrastructure"}', NULL, '2026-03-20 15:03:10.33411', 'https://pods.finance', 'https://github.com/pods-finance', 'https://x.com/PodsFinance', 'https://www.linkedin.com/company/pods-finance', '1e9bf641-c93c-4629-906a-f50db9050164', 'DeFi Infrastructure / Embedded Finance API', 0, NULL, NULL, NULL, false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('62f79ca0-688d-41b6-ac51-bddebc3363f3', 'Merit Systems', 'Building the financial stack for open-source software — enabling agentic commerce through the x402 protocol, developer attribution, and stablecoin-based micropayments.', 'Merit Systems is building infrastructure for what it calls ''Open Source Capitalism'' — a system where open-source software contributors are properly attributed and compensated for the value they create. The company has developed multiple interconnected products: The Terminal (a platform for managing contributor payments and measuring impact in open-source projects), Echo (a model router with user-pays metering for AI inference), and x402scan (an ecosystem explorer for x402, a web standard for stablecoin-based micropayments on any web resource). Their thesis is that agentic AI needs a vast ecosystem of addressable, payable building blocks — and x402 provides the payment rails to make this long tail of services viable.

Founded in 2024 by former a16z and Blockchain Capital engineers, the Brooklyn-based company sits at the intersection of crypto payments, open-source economics, and AI agent infrastructure. The x402 protocol enables just-in-time purchases of API resources using stablecoins without needing a prior relationship with the seller. The company is also building AgentCash — a developer toolkit for agent-to-agent payments — along with services like StableEmail, StableUpload, and StableEnrich that operate as x402-native microservices. With partners including Coinbase, Cloudflare, Vercel, Visa, and Stripe engaged in the x402 ecosystem, Merit is positioning itself as core infrastructure for the emerging agentic commerce economy.', 'Crypto / Web3', 'Infrastructure', 'Seed', 'Seed round: $10M raised in January 2025, co-led by a16z Crypto and Blockchain Capital. Post-money valuation of $55.5M. Notable angel investors include Dan Romero (Farcaster), Anatoly Yakovenko (Solana), Vance Spencer (Framework Ventures), Packy McCormick, Alan Curtis, Chad Byers, Michael Anderson, Cami Ramos, Chris Heaney, Matan Grinberg, Daniel Museles, and Alex Dees.', 'Merit Systems operates in the emerging agentic commerce payments space alongside companies like Skyfire (agent payment infrastructure, backed by Coinbase Ventures and others), Catena Labs (AI-native financial institution for agent identity and payments), and Stripe (which has integrated stablecoin payment features). In the open-source funding space, competitors include GitHub Sponsors and Open Collective. Merit differentiates by focusing on the intersection of open-source economics and agent-native payment infrastructure via the x402 protocol.', 'https://x.com/merit_systems', 'discovered', '{"agentic commerce",x402,"stablecoin payments","open-source funding","AI agent infrastructure"}', NULL, '2026-03-20 17:44:28.448931', 'https://merit.systems', 'https://github.com/merit-systems', 'https://x.com/merit_systems', 'https://www.linkedin.com/company/meritsystems', '1e9bf641-c93c-4629-906a-f50db9050164', 'Payments', 0, NULL, NULL, '[{"title":"x402: An Open Standard for Internet-Native Payments (Whitepaper)","url":"https://www.x402.org/x402-whitepaper.pdf","source":"x402.org / Coinbase","relevance":"The foundational protocol specification that Merit''s entire product suite (x402scan, AgentCash, StableEmail, etc.) is built upon — understanding its technical architecture, payment flow, and facilitator model is essential to evaluating Merit''s protocol-level dependency risk and competitive moat."},{"title":"The GENIUS Act of 2025: Stablecoin Legislation Adopted in the US — Latham & Watkins Analysis","url":"https://www.lw.com/en/insights/the-genius-act-of-2025-stablecoin-legislation-adopted-in-the-us","source":"Latham & Watkins LLP","relevance":"The GENIUS Act (signed July 2025) is the first comprehensive federal stablecoin regulatory framework and directly governs the USDC-based payment rails that underpin all x402 transactions — its issuer requirements, reserve mandates, and state/federal oversight structure define the regulatory ceiling and compliance burden for Merit''s stablecoin micropayment infrastructure."},{"title":"The Value of Open Source Software — Harvard Business School Working Paper No. 24-038","url":"https://www.hbs.edu/ris/Publication%20Files/24-038_51f8444f-502c-4139-8bf2-56eb4b65c58a.pdf","source":"Harvard Business School (Hoffmann, Nagle, Zhou)","relevance":"This seminal study estimates OSS demand-side value at $8.8 trillion while only $4.15 billion on the supply side — quantifying the massive value-capture gap that Merit''s ''Open Source Capitalism'' thesis aims to close through contributor attribution and compensation, and validating the economic rationale for their core product (The Terminal)."},{"title":"The Rise of Agentic Commerce Part 1: New Payment Journeys — Visa Consulting & Analytics Report","url":"https://corporate.visa.com/content/dam/VCOM/corporate/services/documents/vca-rise-of-agentic-commerce.pdf","source":"Visa Consulting & Analytics","relevance":"Visa''s strategic report on agentic commerce evolution maps the four-stage trajectory of AI-initiated payments and the competitive positioning of traditional card networks (Visa''s Intelligent Commerce APIs, Mastercard''s Agent Pay) versus crypto-native protocols like x402 — critical for understanding whether incumbents will co-opt or be displaced by Merit''s approach."},{"title":"Activating HTTP 402: The x402 Protocol and Legal Framework for Internet-Native Stablecoin Payments","url":"https://www.braumillerlaw.com/activating-http-402-the-x402-protocol-and-legal-framework-for-internet-native-stablecoin-payments/","source":"Braumiller Law Group","relevance":"The most comprehensive legal analysis of x402''s regulatory exposure — covering money transmission licensing, GENIUS Act applicability, Federal Reserve oversight of machine-to-machine payments, and the critical question of whether x402 facilitators constitute money transmitters — essential for assessing Merit''s regulatory risk as a core infrastructure provider in this ecosystem."}]', false, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.companies (id, name, one_liner, description, sector, business_model, stage, funding_history, competitive_landscape, source_url, pipeline_stage, tags, image_url, created_at, website_url, github_url, twitter_url, linkedin_url, user_id, sub_sector, deleted_report_count, excitement_score, excitement_reason, adjacent_reads, has_liquid_token, token_tier, token_ticker, token_contract_address, token_chain, liquid_token_analysis) VALUES ('668114ed-2300-4608-9634-324a80cba4b6', 'Ethena Labs', 'Synthetic dollar protocol built on Ethereum that provides a crypto-native stablecoin (USDe) and yield-bearing savings instrument (sUSDe) not reliant on traditional banking infrastructure.', 'Ethena Labs is a decentralized finance protocol that has created USDe, a synthetic dollar and the third-largest stablecoin by market capitalization. Unlike fiat-backed stablecoins such as USDT and USDC, USDe maintains its dollar peg through a delta-neutral strategy combining long spot positions in crypto assets (ETH, BTC, staked ETH) with corresponding short perpetual futures positions. This approach enables Ethena to generate yield from funding rates, staking rewards, and basis spread — revenue that is passed to holders of sUSDe, the protocol''s yield-bearing staked variant. As of August 2025, the protocol had generated over $500 million in cumulative revenue.

Ethena''s product suite has expanded beyond its core synthetic dollar. USDtb is a fiat-backed stablecoin utilizing BlackRock''s BUIDL tokenized treasury fund as reserves. iUSDe wraps USDe in a compliant form for institutional users. The Ethena Whitelabel program provides stablecoin-as-a-service infrastructure, enabling platforms like MegaETH, Jupiter, and Sui to launch their own digital dollars on Ethena''s rails. In partnership with Securitize, Ethena launched Converge, an EVM-compatible blockchain designed as a settlement layer bridging TradFi and DeFi for institutional-grade applications.

Founded in 2023 by Guy Young, a former Cerberus Capital Management executive, Ethena has attracted backing from top-tier investors including Dragonfly, Brevan Howard Digital, Franklin Templeton, Galaxy Digital, Arthur Hayes, and PayPal Ventures, raising approximately $156M in venture funding alongside operating a liquid governance token (ENA).', 'Crypto / Web3', 'Infrastructure', 'Liquid Token', 'Seed Round (Jul 2023): $6.5M led by Dragonfly, with participation from Arthur Hayes, Deribit, Bybit, OKX, BitMEX, Gemini, Huobi, and others. Seed Extension (Feb 2024): $14M led by Dragonfly, with Brevan Howard Digital, Franklin Templeton, Galaxy Digital, Arthur Hayes and others. Valuation reported at $300M. Private Sale (Dec 2024/Feb 2025): $100M — largest round — with Franklin Templeton, F-Prime Capital, Pantera Capital, Polychain Capital, Dragonfly. Strategic round (Mar 2025): $16M from MEXC Ventures. Strategic round (Sep 2025): $20M from M2 Capital. Additional investment from YZi Labs (CZ-linked family office). Total raised approximately $156M+ across multiple rounds from 26+ investors. ENA governance token launched via airdrop on April 2, 2024.', 'Ethena competes in the broader stablecoin market against incumbents Tether (USDT) and Circle (USDC) which together hold over 80% market share. In the synthetic/yield-bearing stablecoin subcategory, Ethena is the dominant player. Competitors include Sky Dollar/USDS (upgraded DAI, MakerDAO-successor) and Falcon USD (hybrid synthetic model with growing traction). Ethena differentiates through its scale, deep exchange integrations (USDe accepted as collateral on Binance and Bybit), yield advantage, institutional-grade infrastructure (iUSDe, USDtb, Converge blockchain), and whitelabel platform.', '', 'discovered', '{Stablecoin,"Synthetic Dollar",DeFi,Yield,"Institutional DeFi","Liquid Token"}', NULL, '2026-03-24 12:03:09.566824', 'https://ethena.fi', 'https://github.com/ethena-labs', 'https://twitter.com/ethena_labs', 'https://www.linkedin.com/company/ethena-labs/', '1e9bf641-c93c-4629-906a-f50db9050164', 'Stablecoins', 0, NULL, NULL, '[{"title":"Fundamentals of Perpetual Futures (He, Manela, Ross, von Wachter — Washington University / a16z)","url":"https://arxiv.org/abs/2212.06888","source":"arXiv / Washington University in St. Louis","relevance":"The seminal academic paper deriving no-arbitrage pricing for perpetual futures and analyzing funding rate dynamics — the exact financial mechanism that generates Ethena''s yield and underpins USDe''s backing, including empirical analysis of how funding rate arbitrage is not risk-free due to the absence of a predetermined expiration date."},{"title":"The GENIUS Act of 2025: Stablecoin Legislation Adopted in the US — Latham & Watkins Analysis","url":"https://www.lw.com/en/insights/the-genius-act-of-2025-stablecoin-legislation-adopted-in-the-us","source":"Latham & Watkins LLP","relevance":"Critical legal analysis of the GENIUS Act (signed July 18, 2025), which prohibits payment stablecoin issuers from offering yield to holders — a provision that directly shapes Ethena''s product architecture, forcing the separation of USDe (non-yielding) from sUSDe (yield-bearing wrapper), and defining the regulatory perimeter that determines whether Ethena''s products are classified as payment stablecoins or fall outside the framework."},{"title":"Coin Metrics State of the Network: Ethena and the Mechanics of USDe — Stress Test Analysis","url":"https://coinmetrics.substack.com/p/state-of-the-network-issue-335","source":"Coin Metrics Research","relevance":"Independent data-driven analysis of USDe''s behavior during the Bybit hack (Feb 2025) and the October 2025 flash crash (USDe hit $0.65 on Binance), examining how funding rates, exchange risk, custody infrastructure, and liquidity dynamics interact under extreme market stress — essential for stress-testing the protocol''s resilience assumptions."},{"title":"Report on Crypto Custody and Off-Exchange Settlement Solutions — Valmar Capital","url":"https://www.valmar.io/blog/report-on-crypto-custody-and-off-exchange-settlement-solutions","source":"Valmar Capital","relevance":"Comprehensive institutional research report analyzing the off-exchange settlement (OES) infrastructure that Ethena depends on (Copper ClearLoop, Ceffu MirrorX, Cobo SuperLoop), including critical assessment of counterparty segregation risks with Ceffu/Binance and the MPC custody architecture that protects billions in Ethena''s backing assets from exchange failures."},{"title":"BlackRock Launches Its First Tokenized Fund, BUIDL, on the Ethereum Network — Official Announcement","url":"https://www.businesswire.com/news/home/20240320771318/en/BlackRock-Launches-Its-First-Tokenized-Fund-BUIDL-on-the-Ethereum-Network","source":"BusinessWire / BlackRock","relevance":"The official launch announcement and structural details of BlackRock''s BUIDL tokenized treasury fund (now $2B+ AUM), which serves as the reserve backing for Ethena''s USDtb fiat-backed stablecoin — understanding BUIDL''s fund structure, custody arrangements (BNY Mellon), Securitize transfer agent role, and Reg D issuance framework is essential to evaluating USDtb''s reserve quality and institutional credibility."}]', true, 'Tier 2', 'ENA', '0x57e114B691Db790C35207b2e685D4A43181e6061', 'ethereum', '

# ENA (Ethena Labs) — Liquid Token Investment Analysis

**Report Date:** March 24, 2026 | **Token Price:** $0.0926 | **Rating: Tier 2 (Average Token)**

---

## 1. Token Classification

**Classification: Tier 2 — Average Token (with potential upgrade path to Tier 1)**

**Decision Tree Application:**

1. **Does the protocol generate meaningful recurring revenue?** → **Yes.** Ethena has generated ~$950M in cumulative fees and ~$600M+ in cumulative revenue since inception. Even at its current depressed run-rate, the protocol generates ~$110–130M annualized in total fees. This is meaningful and recurring, driven by structural demand for basis trade yield and stablecoin infrastructure.

2. **Is revenue high AND growing with strong value accrual to the token?** → **Partially No.** Revenue is cyclical, not consistently growing — total fees collapsed from $54.68M (Jun 2025) to $9.33M (Dec 2025), a ~83% decline. Value accrual to ENA remains **indirect and speculative**: the fee switch has been "met benchmarks" since September 2025 but remains unimplemented as of March 2026. Currently, ~97% of protocol fees flow to sUSDe stakers, with negligible direct value to ENA holders. The DAT buyback program ($890M committed) provides some support, but execution transparency is limited.

3. **Is distribution fair (25–45% initial float)?** → **Marginal.** Initial float at TGE was low (~10–15%), though current circulating supply has reached 56.6%. The allocation is heavily weighted toward insiders: 30% Core Contributors + 25% Investors = 55% to insiders. This exceeds the threshold for concern, though the aggressive buyback program partially offsets.

**Tier 2 rationale:** Ethena generates real, substantial revenue but suffers from (a) high revenue cyclicality tied to funding rate regimes, (b) minimal current value accrual to ENA token holders, (c) insider-heavy distribution with persistent unlock overhang, and (d) a pending but undelivered fee switch that has been "imminent" for over six months. Upgrade to Tier 1 is contingent on fee switch activation, revenue stabilization, and completion of the unlock schedule.

---

## 2. Supply & Adjusted Market Cap

### Supply Breakdown

