INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('8ddb6d7e-931e-4fee-ba36-c6db54b15b57', '3876a3ca-4691-45e3-a146-84592b79b099', 'Patrick Collison', 'CEO', 'Irish entrepreneur who co-founded Stripe at age 22. Previously co-founded Auctomatic, a software company for managing online auctions, which was acquired by Live Current Media in 2008 for $5 million when he was 19. Studied at MIT before dropping out to build Stripe. Named to Forbes 30 Under 30 and has become one of the youngest self-made billionaires.', 'https://www.linkedin.com/in/patrickcollison/', '', 'Auctomatic', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('6abb97d7-057f-4e7c-9b47-c26bec6b295e', '3876a3ca-4691-45e3-a146-84592b79b099', 'John Collison', 'President', 'Irish entrepreneur and younger brother of Patrick Collison, who co-founded Stripe at age 20. Also co-founded Auctomatic with Patrick. Studied physics at Harvard before dropping out to focus on Stripe. At one point was the world''s youngest self-made billionaire. Known for his technical depth and operational focus at Stripe.', 'https://www.linkedin.com/in/johncollison/', '', 'Auctomatic', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('9df41891-93b9-4183-889f-8be0276437c8', '0ba6a757-40e2-47d3-88cf-702b82a46aa4', 'Dylan Field', 'CEO & Co-founder', 'Dylan Field dropped out of Brown University to start Figma after receiving a Thiel Fellowship in 2012. He previously interned at Flipboard and LinkedIn. He has led Figma from inception to becoming the dominant design platform in the industry, navigating through the attempted Adobe acquisition and continuing to lead the company as an independent entity.', 'https://www.linkedin.com/in/dylanfield/', '', 'Flipboard, LinkedIn', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('5af6f85b-eb09-48ae-862f-1bc6c5a45659', '0ba6a757-40e2-47d3-88cf-702b82a46aa4', 'Evan Wallace', 'Co-founder & former CTO', 'Evan Wallace co-founded Figma with Dylan Field after they met at Brown University. A highly skilled engineer, Wallace was instrumental in building Figma''s core technology, including its browser-based rendering engine built on WebGL. He departed Figma in 2021 but remains recognized as a technical co-founder. He studied computer science at Brown University.', 'https://www.linkedin.com/in/evan-wallace-a3741914/', '', '', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('58c6dfde-2c96-4618-b470-54feba6c725c', '1afbd370-5e53-479c-a9db-83496e5a7e05', 'Aditya (Adi) Baradwaj', 'Founder and CEO', 'Former software engineer at Alameda Research (Sep 2021 - Nov 2022), where he later spoke publicly about the firm''s engineering and security failures and testified as a witness at the SBF fraud trial. Previously software engineer at Google. Served as Instructor at UC Berkeley (CS 188: Introduction to Artificial Intelligence, Summer 2019) and was affiliated with Berkeley Artificial Intelligence Research (BAIR). Educated at UC Berkeley. Founded Astra in 2023 after the FTX/Alameda collapse.', '', '', 'Alameda Research, Google, UC Berkeley, Berkeley Artificial Intelligence Research', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('3bb478e3-7081-4473-9612-48077302769c', 'db3343bc-f929-4600-bf39-cd85d2951f0f', 'Alex Momot', 'Founder & CEO', 'Ukrainian entrepreneur with over a decade of IT experience, immersed in blockchain since 2013. Previously founded Remme, a blockchain-based authentication/PKI company. Board Member of the Bitcoin Foundation Ukraine. Launched BitX in 2014 (Bitcoin payments for telecom). Participated in creating Ukrainian miners Hotmine on Bitfury chips. Early Ethereum ICO investor. Master''s degree in International Finance from Kiev National Economic University (2003-2008). Based in Lisbon, Portugal.', 'https://www.linkedin.com/in/alex-momot-93596b32', 'https://x.com/amomot86', 'Remme (Founder & CEO), BitX, Agro Capital LLC, Hotmine', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('fe81a23d-3e36-4b5f-8c56-684562304f48', 'cda62790-cb76-4573-9997-009a560f3929', 'Muhammad Awan', 'Founder', 'Co-founder of Sequence Markets (YC W26). Based in the Mississauga/Toronto area.', 'https://www.linkedin.com/in/muhammad-awan0/', '', '', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('ffa00dd4-2891-491a-9d98-444e69c36d50', 'cda62790-cb76-4573-9997-009a560f3929', 'Peter Bai', 'Founder', 'Co-founder of Sequence Markets (YC W26). Based in San Francisco. Self-described interest in market structure.', 'https://www.linkedin.com/in/peter-bai/', '', '', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('6a1252b8-27a1-4b35-ae8d-22738398d503', 'a21e42fd-647e-4be2-a9fe-5ef31806ec97', 'Anil Lulla', 'Co-Founder & CEO', 'Co-Founder of Delphi Digital. Previously worked as a Leveraged Finance CRM Associate at Deutsche Bank covering Retail and TMT sectors. Before Deutsche Bank, was a Corporate Bonds Analyst at Bloomberg L.P. Attended Rutgers Business School (2010-2014).', 'https://www.linkedin.com/in/anillulla', 'https://x.com/anildelphi', 'Deutsche Bank, Bloomberg', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('f2afac76-c92d-4871-abc6-fe93a9b8b677', 'a21e42fd-647e-4be2-a9fe-5ef31806ec97', 'Kevin Kelly', 'Co-Founder & Head of Research / Global Head of Macro Strategy', 'Co-Founder of Delphi Digital. CFA charterholder. Core focus lies at the intersection of global macroeconomic trends, financial markets, and crypto/digital assets. Previously spent nearly 12 years at Bloomberg Intelligence as a U.S. Equity Strategist. Holds a BA in Business Administration (Finance and Economics) from University of Dayton (2010-2014).', 'https://www.linkedin.com/in/kevin-kelly-cfa-02027b28/', '', 'Bloomberg', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('4f44a642-800a-4291-a7b2-25039180853c', 'cea9364f-37df-49d1-9aaf-fd9aab1363e4', 'Ruchi Dubey', 'People & Culture Director, METRO Global Solution Center India', 'Ruchi Dubey leads the People & Culture function at METRO GSC India. She was appointed as a Whole-time Director on August 21, 2025, per Indian corporate filings, and was recognized as a key leader during the September 2025 Pune office inauguration.', 'https://www.linkedin.com/in/ruchidubey/', NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('23972296-ec05-456d-a2b5-f6432de48fd9', 'a21e42fd-647e-4be2-a9fe-5ef31806ec97', 'Medio Demarco', 'Co-Founder', 'Co-Founder of Delphi Digital. Previously an Associate in Deutsche Bank''s risk department in New York, responsible for derivatives exposure, legal negotiations, structured financing, and equity loans for hedge fund clientele. Before that, was a Fixed Income Analyst at Bloomberg L.P. covering U.S. corporate bonds and Treasuries.', '', '', 'Deutsche Bank, Bloomberg', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('65877736-18c2-47fa-a9f5-ff94a83fc7db', 'a21e42fd-647e-4be2-a9fe-5ef31806ec97', 'Tom Shaughnessy', 'Co-Founder & Founding Partner (Delphi Ventures)', 'Co-Founder of Delphi Digital and Founding Partner of Delphi Ventures. Host of The Delphi Podcast. Previously an Equity Research Analyst at Oppenheimer & Co. covering cloud and communication infrastructure providers. Also founded 51percent Crypto Research and worked at Dane Capital Management. Attended Rutgers Business School.', '', 'https://x.com/Shaughnessy119', 'Oppenheimer & Co., Dane Capital Management, 51percent Crypto Research', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('900b981a-577f-4b98-86cf-48100b90b8e0', 'a21e42fd-647e-4be2-a9fe-5ef31806ec97', 'Yan Liberman', 'Co-Founder', 'Co-Founder and Managing Partner of Delphi Ventures. Previously an Equity Research Associate at Bloomberg Intelligence covering the global technology sector. Before that, worked as a Dividend Forecasting Analyst at Bloomberg L.P. Also worked at Deutsche Bank''s Leveraged Finance CRM group covering the Retail sector. CFA and CAIA charterholder.', '', '', 'Bloomberg, Deutsche Bank', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('e5966625-7c6d-40dc-a46e-2bdc70ae18ff', 'f363f359-7428-471d-8f12-31ad7c78bdd4', 'Nitesh Gupta', 'Co-Founder and CEO', 'Based in New York. Tufts University alumnus. Previously worked at Magna, Carta, Vise, and Bloomberg. Previously wound down a startup called Cybersyn. Also involved in venture investing, having worked with Foundation Capital.', 'https://www.linkedin.com/in/niteshvgupta', NULL, 'Magna, Carta, Vise, Bloomberg', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('77444f17-a697-43b7-8624-8a670e685ce3', 'f363f359-7428-471d-8f12-31ad7c78bdd4', 'Nirel Gershwind', 'Co-Founder', 'Based in New York. University of Maryland alumnus. Previously worked at CosMove, Mira Finance, Lockheed Martin, and the National Science Foundation (NSF). Described as an early fanatic of Helium and security-first blockchain languages like Move.', 'https://www.linkedin.com/in/nirel-gershwind/', NULL, 'CosMove, Mira Finance, Lockheed Martin, National Science Foundation (NSF)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('3bc68f76-6964-489a-8db0-ed8caca23625', '87465d6c-d80c-4803-ab52-40a7c9a93f4f', 'Louis Régis', 'Founder & CEO of XBorg (parent company / studio that built Propr)', 'Founder & CEO of XBorg, the studio behind Propr. XBorg is a spin-off of SwissBorg. Based in Dubai.', 'https://www.linkedin.com/in/louisregis/', NULL, 'SwissBorg (ecosystem)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('6180bca6-ff1c-4f43-8360-173cd3339dce', 'e4eea46b-0872-4098-b0ec-da12ffeb1ece', 'Berkay Hacifettahoglu', 'Founder', 'Based in Istanbul, Turkey. Attended Turkish-German University (Computer Science, dropped out). Previously served as COO at Midle (a task-to-earn Web3 marketing platform in the GAMI Technology ecosystem) where he spoke at Cointelegraph X Spaces. Also worked at GAMI Technology as a Product Manager. Completed a production internship at Danone.', 'https://www.linkedin.com/in/berkayhfo/', 'https://x.com/0xhfo', 'Midle (COO), GAMI Technology (Product Manager), Danone (Intern)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('bc652e34-79c1-4ea5-af8d-073791c52119', '3d49234e-2717-4407-ac7c-7f062f22bc96', 'Sumer Malhotra', 'Co-founder & CEO', 'Sumer Malhotra is the Co-founder and CEO of Fireplace, leading the company''s vision to build the Bloomberg Terminal equivalent for prediction markets. He is based in Hong Kong, where Fireplace operates from, and educated at The University of Hong Kong. His understanding of both TradFi execution standards and crypto-native infrastructure positions him to bridge institutional trading expectations with decentralized prediction market venues.', 'https://www.linkedin.com/in/sumermalhotra/', 'https://x.com/buuxbt', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('45c9ff86-5169-41a7-944a-0808642d2b96', '3d49234e-2717-4407-ac7c-7f062f22bc96', 'Akshay Rajagopal', 'Co-founder & CTO', 'Akshay Rajagopal is the Co-founder and CTO of Fireplace, responsible for the platform''s technical architecture including real-time data infrastructure, smart order routing, and cross-venue execution. He is also a Co-founder of Enclave Money, the chain-abstracted wallet and liquidity infrastructure that powers Fireplace''s wallet technology and cross-chain automations. Prior to Fireplace, he worked at Xalts as Engineering Lead for Blockchain and Frontend, and at Amazon as a Software Development Engineer. He studied at BITS Pilani.', 'https://www.linkedin.com/in/akshay-rajagopal-780747128/', 'https://x.com/akshayraj_v0', 'Enclave Money, Xalts, Amazon', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('0e9c0b44-0312-446e-9947-8b0ebbc15ca9', '084ae8fd-fe6f-4878-afec-857f488cf36f', 'Marco van den Heuvel', 'Co-founder (via Beam Foundation)', 'Marco van den Heuvel is the co-founder and CGO of the Beam Foundation (formerly Merit Circle DAO), the parent ecosystem behind Dreamcash. He has been involved in crypto since 2017, building one of the most recognized gaming DAOs in Web3. Under his leadership, Beam expanded from an Axie Infinity guild into a multi-division Web3 organization spanning gaming, ventures, and now trading via Dreamcash. He was quoted speaking on behalf of Dreamcash regarding the Tether investment. He attended Arnhem Business School and has served as a GAM3 Awards juror. He has built strategic partnerships with Polygon Labs and Immutable for the Beam ecosystem.', 'https://www.linkedin.com/in/marcovdheuvelnl/', 'https://x.com/Marco_Beam', 'Beam Foundation / Merit Circle DAO (Co-founder & CGO)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('d18978e2-5e0b-4fbc-b433-6630a875a694', '084ae8fd-fe6f-4878-afec-857f488cf36f', 'Hubert Johnson', 'Head of Marketing', 'Hubert Johnson serves as the Head of Marketing at Dreamcash and has been the primary spokesperson in press releases and media announcements, including the platform''s August 2025 launch announcement distributed via Chainwire across outlets including Decrypt and CryptoBriefing. Limited public information is available about his prior background.', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('31320a18-74c0-4e4c-92f0-dc0c31325164', 'cea9364f-37df-49d1-9aaf-fd9aab1363e4', 'Sreeman N Murthy Kandala', 'CEO, METRO Global Solution Center India', 'Sreeman Murthy serves as CEO of METRO Global Solution Center India, leading the organization''s operations across finance, IT, data analytics, and business solutions. Under his leadership, MGSC inaugurated a new office in Pune on September 2, 2025. He is listed as Managing Director in Indian corporate filings.', 'https://www.linkedin.com/in/sreeman-n-murthy-kandala-5830a35', NULL, 'Genpact', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('c31bda5d-1812-4652-aa9b-4d8be0bf01f2', 'cea9364f-37df-49d1-9aaf-fd9aab1363e4', 'Michael Bouscheljong', 'SVP – Corporate Accounting & Global Solution Center (METRO AG)', 'Michael Bouscheljong is the Senior Vice President of Corporate Accounting and Global Solution Center at METRO AG, providing executive oversight of the MGSC operations from the parent company side. He was appointed as a Director of MGSC on February 1, 2024, per Indian corporate filings.', NULL, NULL, 'METRO AG', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('155c40ed-8cd5-4b9c-a3a9-f0dab34356e9', 'cea9364f-37df-49d1-9aaf-fd9aab1363e4', 'Mehmet Tevfik Durmusoglu', 'Director, METRO Global Solution Center India', 'Mehmet Tevfik Durmusoglu serves as Director at METRO Global Solution Center India. He was appointed as Director on October 9, 2024, per Indian corporate filings. He was among the senior leaders present at the inauguration of MGSC''s new Pune office in September 2025.', 'https://www.linkedin.com/in/mehmet-tevfik-durmusoglu-71846416/', NULL, 'BMGI, Borusan Holding', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('b09e7e52-00d0-48c2-9b60-97870e3f2097', 'cf7b4843-c645-4e2e-a206-b674f04a08ec', 'Jeffrey Quesnelle', 'Co-founder & CEO', 'Jeffrey Quesnelle brings a rare combination of deep systems engineering and crypto/MEV expertise to the CEO role at Nous Research. He holds an M.S. in Computer Science from the University of Michigan and spent over 15 years in software engineering, including as Director of Software Development at Intrepid Control Systems (automotive/in-vehicle networking) and as an MEV Engineer at Eden Network (blockchain). His master''s thesis analyzed anonymity in the Zcash cryptocurrency, and he co-authored ''Automotive Ethernet - The Definitive Guide.'' At Nous, he co-authored the DeMo paper alongside Bowen Peng and Diederik Kingma (Adam optimizer co-inventor), representing a foundational research contribution in distributed training. He is also a co-author of YaRN, an efficient context window extension method for LLMs that gained significant traction in the open-source community.', 'https://www.linkedin.com/in/jeffrey-quesnelle-2490a524/', 'https://x.com/theemozilla', 'Eden Network (MEV Engineer), Intrepid Control Systems (Director of Software Development)', 'https://github.com/jquesnelle', 'https://jeffq.com') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('1349ab6a-158c-45f4-bd62-4faa489b6807', 'cf7b4843-c645-4e2e-a206-b674f04a08ec', 'Karan Malhotra', 'Co-founder & Head of Behavior', 'Karan Malhotra serves as Head of Behavior at Nous Research, overseeing the behavioral alignment and data synthesis strategies that have made the Hermes model family one of the most popular open-source LLM series. Prior to Nous, he was a Machine Learning Researcher at the Stanford Brain Stimulation Lab. He studied Religion and Philosophy at Emory University, an unconventional background that informs Nous''s philosophical approach to uncensored, human-centric AI. Malhotra has been a primary public spokesperson for Nous, articulating the company''s vision at the intersection of open-source AI and crypto incentive mechanisms in interviews with Fortune, The Block, and other outlets.', NULL, 'https://x.com/karan4d', 'Stanford Brain Stimulation Lab (ML Researcher)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('85f560e1-22bc-45e5-9b6d-8ee7764c8f88', 'cf7b4843-c645-4e2e-a206-b674f04a08ec', 'Teknium (Ryan Teknium)', 'Co-founder & Head of Post Training', 'Teknium is the creator of the Hermes family of models — arguably the most well-known and widely downloaded open-source fine-tuned LLM series — and leads all post-training efforts at Nous Research. He brings deep practical expertise in LLM fine-tuning, data synthesis pipelines, and reinforcement learning from human feedback. He built DataForge, Nous''s graph-based synthetic data generation system, and the OpenHermes datasets that have been used across the open-source community. With a significant following on X/Twitter, Teknium is one of the most influential voices in the open-source AI community, and his model releases (including StableBeluga/Free Willy 2, the Orca replication) consistently drive significant community engagement and adoption.', NULL, 'https://x.com/Teknium1', NULL, 'https://github.com/teknium1', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('5f23faf5-172e-410b-853f-742d44fdb615', 'cf7b4843-c645-4e2e-a206-b674f04a08ec', 'Shivani Mitra', 'Co-founder', NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('a558a705-6e77-48ee-b731-f1fb88fc44f5', 'b42d2a15-8eeb-4bcd-95f2-d920edfb373b', 'MovieTime (pseudonymous)', 'Founder', 'Pseudonymous founder known as ''MovieTime'' (@MovieTimeDev), who has built a notable audience in the prediction markets space with individual posts reaching hundreds of thousands of views, demonstrating domain expertise in prediction market mechanics and arbitrage strategies between Polymarket and Kalshi. Their content has been syndicated on platforms like OKX. Real identity and prior professional background are not publicly known.', NULL, 'https://x.com/MovieTimeDev', NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('3d3efcbf-412c-4b5b-8f12-481c41b90484', 'd847ed3e-e67f-44a7-9c65-5d8dd5c34b0d', 'Lihong Wang', 'Founder & CEO', 'Lihong is a former quantitative trader who interned at Jane Street (summer 2023) and Akuna Capital (summer 2022), then joined IMC Trading as a full-time quantitative trader, where he built mid-frequency trading algorithms. He holds a B.S. in Math & Statistics from Duke University (graduated 2024). His core insight for Freeport comes from experiencing the gap between trading with full institutional coverage (analyst support, real-time news, positioning data) versus trading blind in personal accounts — he''s building the AI layer that democratizes that situational awareness. He is crypto-native and has personally traded profitably on DEXs, bridging deep TradFi quantitative expertise with DeFi execution.', 'https://www.linkedin.com/in/lihong062/', NULL, 'IMC Trading (Quantitative Trader), Jane Street (Quant Trading Intern), Akuna Capital (Quant Trading Intern), Saba Capital Management', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('4a3033b8-4751-422a-a530-67f3d207d848', 'd847ed3e-e67f-44a7-9c65-5d8dd5c34b0d', 'Bryan Reed', 'Co-founder & CTO', 'Bryan is a deeply technical co-founder with software engineering experience at Huawei and Capital One. Before Freeport, he founded SailLoft, an AI-enabled software testing SaaS, during his senior year of college, scaling it to $240K in revenue with 4 employees — demonstrating early entrepreneurial drive and the ability to build and ship product with minimal resources. He studied Math & Computer Science at the University of North Carolina at Chapel Hill.', 'https://www.linkedin.com/in/bryan-reed-87ab5920a/', NULL, 'SailLoft (Founder), Huawei, Capital One', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('143a8d5d-5d74-48fa-b8d1-af7faf9c8d9e', 'd847ed3e-e67f-44a7-9c65-5d8dd5c34b0d', 'Mason Sufnarski', 'Head of Growth', 'Mason leads go-to-market at Freeport Markets, driving social media and in-person growth initiatives. He previously worked at JP Morgan in Digital Assets. He holds a B.S. in Mechanical Engineering & Materials Science from Duke University.', 'https://www.linkedin.com/in/masonsufnarski/', NULL, 'JP Morgan (Digital Assets)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('00f618b3-0513-4f55-9846-2a0ffe29053e', '059dc521-995e-4dd9-91b5-edb1b8614c2d', 'Eileen Dai', 'Co-founder (original Tare Inc; current involvement uncertain)', 'Eileen Dai co-founded the original Tare Inc. in 2023 alongside Max Sidebotham, initially building an AI-powered email marketing platform for e-commerce brands. Prior to founding Tare, she was the Founding Product Designer at Skio and a Product Designer at Robinhood. She gained earlier design experience through roles at Workday and Hewlett Packard Enterprise. She is currently listed as a Product Designer at Ramp, suggesting she may no longer be actively involved with Tare''s consumer lending pivot.', NULL, NULL, 'Ramp (Product Designer), Robinhood (Product Designer), Skio (Founding Product Designer), Workday (Product Design Intern), Hewlett Packard Enterprise (Design Intern)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('e122afb1-8d24-4e4e-8df9-b125d3b8e74c', '059dc521-995e-4dd9-91b5-edb1b8614c2d', 'Max Sidebotham', 'Co-founder & CTO (original Tare Inc; current involvement uncertain)', 'Max Sidebotham co-founded Tare in 2023 and served as Co-founder & CTO through 2024. Before Tare, he was a Founding Engineer at Skio and a Software Engineer at Robinhood (2020-2022). He graduated Magna Cum Laude from Rutgers University Honors College with a B.S. in Computer Science and a minor in Cognitive Science. He currently serves as a Founding Engineer at Icon, suggesting he is no longer actively leading Tare''s new consumer lending direction.', 'https://www.linkedin.com/in/max-sidebotham/', NULL, 'Icon (Founding Engineer), Skio (Founding Engineer), Robinhood (Software Engineer), University of Maryland BAM Research Lab', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('f277275c-3dfb-4989-a158-85f6dadaebf6', 'f8b303b0-f5be-4420-9a69-b497897a7350', 'Mason', 'Co-founder', 'Co-founder of Mirage Protocol. Part of a small team building modular money infrastructure on Move-based ecosystems. Further background details are not publicly available due to the pseudonymous nature of the team.', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('ae83b2a1-6613-4ffc-aa5a-4aba7655a3c3', 'f8b303b0-f5be-4420-9a69-b497897a7350', 'Moon Shiesty', 'Co-founder / Core Developer', 'Core developer at Mirage Protocol who has established himself as a technically influential builder in the Aptos ecosystem. He co-authored Aptos AIP-119 alongside Sherry Xiao (Aptos Labs'' Head of Production Engineering) to reduce staking rewards — a highly visible governance proposal demonstrating ecosystem-level influence. Actively contributes to Aptos core development. His GitHub shows contributions spanning protocol smart contracts, SDKs, and Aptos core infrastructure.', NULL, 'https://x.com/moonshiesty', NULL, 'https://github.com/MoonShiesty', NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('14d08bd7-ebba-4e92-b4c9-a7dc73625800', '1b06af05-1b8d-4312-8cd4-b0de8fad4245', 'Samuel Dare', 'Founder', 'Samuel Dare is a blockchain veteran with over eight years of experience in emerging technologies who founded Templar (now Covenant AI) on Bittensor Subnet 3. His prior experience spans co-founding Khalani (a decentralized intents/solver protocol), serving as CTO of Akropolis (DeFi protocols), and working as Technical Lead for Blockchain at Shell. Educated at Oxford''s Saïd Business School, Dare brings a combination of deep blockchain infrastructure expertise and DeFi protocol design experience to the challenge of decentralized AI training. He has led the team to produce two research papers accepted at a NeurIPS workshop and successfully trained a 72B-parameter model on fully decentralized infrastructure.', 'https://www.linkedin.com/in/samuel-b-dare/', NULL, 'Khalani (Co-founder), Akropolis (CTO), Shell (Technical Lead - Blockchain), Brave Software (Blockchain Architect), SapientRazorfish', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('db469390-2797-4e98-8911-022bd0d4ef76', '1b06af05-1b8d-4312-8cd4-b0de8fad4245', 'Evangelos Pappas', 'Co-founder', 'Evangelos ''Evan'' Pappas is a co-founder of Covenant AI who serves as both a strategic leader and hands-on developer across the ecosystem''s three subnets (Templar, Basilica, Grail). He is a public evangelist for the Bittensor ecosystem and the decentralized AI vision, and plays a key coordination role across the three interconnected platforms. His background spans blockchain engineering with a strong vision for decentralized AI infrastructure.', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('1a0d6fad-22aa-4ded-8aa2-464737a39578', '1b06af05-1b8d-4312-8cd4-b0de8fad4245', 'Joel Lidin', 'AI Researcher & Engineer', 'Joel Lidin contributes to the machine learning research efforts at Covenant AI. His work on the MMLU curves for Covenant72B demonstrated reasoning breakthroughs in decentralized training. His AI research background complements the blockchain expertise of the other team members.', NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('8971c646-9b73-4ccd-9189-77d30fa54cd5', '7b376c2e-4c39-4ddb-83f8-768d0d8ad203', 'Sonya Kim', 'Co-founder', 'Sonya Kim brings a rare combination of institutional finance pedigree and deep DeFi operational experience. Before co-founding 3F, she served as ''Chef'' at Steakhouse Financial — one of DeFi''s most influential risk curation and DAO advisory firms — where she led business development and grew Morpho''s TVL from zero to $1 billion. Prior to DeFi, she was a portfolio manager at Progrmd Capital (a specialist crypto investment firm). She cut her teeth at institutional asset managers including Baillie Gifford (Investment Risk Analyst), Kiltearn Partners (Investment Analyst), and Aberforth Partners (Investment Manager). She holds a Master of Finance from MIT and a BA in Mathematics with a minor in Computer Science from NYU.', 'https://www.linkedin.com/in/sonyakim/', 'https://x.com/sonyasunkim', 'Steakhouse Financial (Chef / BD Lead), Progrmd Capital (Portfolio Manager), Aberforth Partners (Investment Manager), Kiltearn Partners (Investment Analyst), Baillie Gifford (Investment Risk Analyst)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('c50926e7-32a3-4141-8f88-eb8b761babcf', '7b376c2e-4c39-4ddb-83f8-768d0d8ad203', 'Romeo Ravagnan', 'Co-founder', 'Romeo Ravagnan comes from the institutional crypto hedge fund world, having served as DeFi Lead at Abraxas Capital Management — a London-based, FCA-regulated digital asset manager known for its award-winning Elysium Global Arbitrage Fund and as one of Tether''s largest institutional clients. His background in institutional-grade crypto arbitrage strategies directly informs 3F''s approach to bringing leveraged, institutional-quality yield strategies on-chain.', 'https://www.linkedin.com/in/romeoravagnan/', 'https://x.com/3f_romeo', 'Abraxas Capital Management (DeFi Lead)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('3ee19a32-2744-4ec8-a5a3-f61f0df95423', '38d9978a-a8ed-4d34-8874-608a79b213ee', 'Alex Gedevani', 'Founder', 'Alex Gedevani brings deep crypto-native expertise spanning research, investment, and ecosystem development. He has served on the Ecosystem team at Monad Foundation and previously held roles as Investment Associate at Sfermion (an NFT-focused fund), Ventures and Research Associate at Delphi Digital (one of crypto''s most respected research firms), Financial Analyst at Barclays, and Community Analyst at Messari. His trajectory from traditional finance through crypto research and investment to ecosystem building and now founding gives him a rare combination of financial rigor, market intelligence, and hands-on crypto ecosystem knowledge. He was an early beta user of NBA Top Shot (top 50 account), demonstrating deep personal conviction at the intersection of sports and crypto that directly informs WeLikeSports'' thesis.', 'https://www.linkedin.com/in/alexgedevani/', 'https://x.com/alexgedevani', 'Monad Foundation (Ecosystem), Sfermion (Investment Associate), Delphi Digital (Ventures & Research Associate), Barclays (Financial Analyst), Messari (Community Analyst)', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('1fff6284-25d3-4f94-9eaf-dc5548da72fa', '1856f2b2-f134-4455-9a94-d8ae2f4a1f41', 'Abram Dawson', 'Founder', 'Abram Dawson is one of the founders of Splits, where the team is building financial infrastructure for onchain teams. Before founding Splits, he worked at SV Angel, one of Silicon Valley''s most prestigious seed-stage firms, where he joined in 2012 and was included in Forbes Magazine''s 30 under 30 in 2016. At SV Angel he sourced investments and worked closely with portfolio companies. After leaving SV Angel, he spent time as an independent consultant and angel investor before co-founding Splits, which originated from an ETHGlobal hackathon project. He studied Economics and International Business at Santa Clara University''s Leavey School of Business.', 'https://www.linkedin.com/in/abramdawson/', '', 'SV Angel', '', 'https://www.anabram.com/') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('b8b14ecc-76b3-44f3-90e7-1eca88c9e698', '1856f2b2-f134-4455-9a94-d8ae2f4a1f41', 'William Minshew', 'Co-founder', 'William Minshew is a San Francisco-based co-founder of Splits who has been guiding product development and growth strategy since 2021. He holds a BEng in Electrical and Electronics Engineering from Princeton University, where he won the Hisashi Kobayashi Award for Computing Excellence and the Shapiro Prize for Academic Excellence. Before Splits, he founded Emrys and co-founded Canvas, where he built computer vision-based retail analytics using camera feeds and deep learning models. His earlier career included roles at The Blackstone Group and Cadre, giving him a blend of financial acumen and engineering experience well-suited to building financial infrastructure.', 'https://www.linkedin.com/in/william-minshew/', 'https://twitter.com/wminshew', 'Emrys (Founder), Canvas (Co-founder), Cadre (Director), The Blackstone Group', 'https://github.com/wminshew', 'https://www.willminshew.com') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('6b366b08-1fa6-4216-8b12-0f0f49a2d19f', 'c093f41d-ae81-45dd-98f5-94641ff1a725', 'Rafaella Baraldo', 'Co-founder & CEO', 'Rafaella brings deep traditional finance expertise to the DeFi infrastructure space, having worked at Barclays, Itaú BBA, Revmob, and Supernova Coins before co-founding Pods in 2020. She studied Business Administration at FGV-EAESP and previously worked at Mainframe (later Hifi Finance) alongside her co-founders. She is a recognized DeFi thought leader in Latin America, speaking at major industry events including Consensus Hong Kong 2025, and has been instrumental in securing partnerships with Brazil''s core financial infrastructure players including Núclea and participation in the DREX initiative. Under her leadership, the company has raised over $12M and pivoted from a consumer DeFi protocol to a B2B infrastructure play targeting the LatAm neobank market.', 'https://www.linkedin.com/in/rafaellabaraldo/', '', 'Barclays, Itaú BBA, Mainframe, Supernova Coins, Revmob', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('f6ef1585-dfeb-4adc-8a82-55a6fdc20119', 'c093f41d-ae81-45dd-98f5-94641ff1a725', 'Robson Silva Junior', 'Co-founder & CTO', 'Robson is a full-stack blockchain developer and serial crypto entrepreneur who co-founded Ohmydefi!, one of the first option contracts built on Ethereum (ETHDenver hackathon finalist), and previously co-founded 314Coins, a Brazilian crypto aggregator exchange. With a Naval Engineering degree from Escola Politécnica da USP, he brings rigorous technical fundamentals to smart contract architecture. At Mainframe (later Hifi Finance), he researched and architected a fixed-rate lending protocol and built yield aggregators interacting with bZx, Compound, and dYdX — directly relevant experience for Deframe''s current lending/yield API products. He has been deeply involved in Brazil''s DREX blockchain initiative, representing Pods at B3 (Brazilian stock exchange) discussions on tokenized finance.', 'https://www.linkedin.com/in/robsonsjre/', '', 'Mainframe/Hifi Finance, 314Coins, Ohmydefi!, RevMob, BelugaDB', 'https://github.com/robsonsjre', 'https://robsonsjre.github.io/') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('1b191088-bef8-4d1f-9978-b41123bff5a9', 'c093f41d-ae81-45dd-98f5-94641ff1a725', 'Guilherme Guimarães', 'Co-founder & VP Engineering', 'Guilherme is a full-stack developer who serves as VP of Engineering at Pods. Prior to Pods, he was a Software Engineer at Hifi Finance (formerly Mainframe). He also previously worked at Celebryts, Cuattro Trade Marketing, and IBIZ Tecnologia. He holds a Computer Engineering degree from FATEC-SP.', '', '', 'Hifi Finance/Mainframe, Celebryts, Cuattro Trade Marketing, IBIZ Tecnologia', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('f4e7f10c-2075-4c64-ba42-36e8877ff0fd', '62f79ca0-688d-41b6-ac51-bddebc3363f3', 'Sam Ragsdale', 'Co-founder & CEO', 'Sam Ragsdale brings a rare blend of engineering depth and venture pattern recognition to Merit. Prior to founding the company, he was an Investment Engineer at a16z crypto, where he worked on Jolt, a zero-knowledge virtual machine (zkVM), and supported the investing process. Before a16z, he was a software engineer at Google and also worked at Blockchain Capital. He met co-founder Ryan Sproule as an undergraduate at Washington University in St. Louis, and the two have been collaborating for nearly a decade. His deep expertise spanning blockchain cryptography, open-source ecosystems, and venture investing gives him a unique vantage point on how to build sustainable economic models for open-source software.', 'https://www.linkedin.com/in/sam-ragsdale-2ba55b122', 'https://x.com/samrags_', 'a16z crypto (Investment Engineer), Google (Software Engineer), Blockchain Capital', 'https://github.com/sragss', 'https://www.samragsdale.com/') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('ba7a73bc-ae4b-48ce-a387-5410d38493b7', '62f79ca0-688d-41b6-ac51-bddebc3363f3', 'Ryan Sproule', 'Co-founder & CTO', 'Ryan Sproule is a systems-level engineer who combines deep crypto infrastructure experience with production-grade backend expertise. Before co-founding Merit, he was a research engineer at Blockchain Capital, a premier crypto-dedicated venture fund, where he helped spearhead technical research initiatives, make investments, and advise portfolio companies. Prior to that, he was a software engineer at Amazon Web Services, giving him extensive experience building scalable cloud infrastructure. Ryan and Sam have been collaborating since meeting at Washington University in St. Louis nearly a decade ago. As CTO, Ryan leads the technical architecture of Merit''s x402 ecosystem and has been described by Blockchain Capital as an ''exceptionally talented engineer'' and BCAP alumni.', 'https://www.linkedin.com/in/ryansproule', '', 'Blockchain Capital (Research Engineer), Amazon Web Services (Software Engineer)', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('5db007a4-a1bd-4dcc-a28d-c81375e3dd46', '62f79ca0-688d-41b6-ac51-bddebc3363f3', 'Mason Hall', 'Co-founder & Head of Strategy', 'Mason Hall rounds out the Merit founding team with a rare dual background in crypto investing and hands-on engineering. He was a Partner on the Crypto Investments team at Andreessen Horowitz, giving him firsthand knowledge of how the top crypto fund evaluates protocol-level opportunities. Before a16z, he was a software engineer at bloXroute Labs, a blockchain infrastructure company focused on network-layer scaling. He also held roles at ConsenSys Ventures. Mason''s combination of deal-sourcing experience and deep technical chops makes him particularly effective at strategy, partnerships, and fundraising — skills critical to growing Merit''s ecosystem of x402 participants and enterprise partners.', 'https://www.linkedin.com/in/hallmason', '', 'Andreessen Horowitz (Partner, Crypto Investments), bloXroute Labs (Software Engineer), ConsenSys Ventures', 'https://github.com/fmhall', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('311b9ae9-af34-43ba-9bbf-617d8d4ba71a', '62f79ca0-688d-41b6-ac51-bddebc3363f3', 'Sharif Elfouly', 'Engineer', 'Known as ''Shafu'' on GitHub, Sharif Elfouly is a founding engineer at Merit Systems who has been contributing extensively to the x402scan and AgentCash codebases. He was welcomed to the team with mention of his ''deep expertise'' and is one of the most prolific contributors to Merit''s open-source repositories. He is the author of ''EVM from Scratch,'' a guide to implementing the Ethereum Virtual Machine, and hosts the ''Push & Pop'' podcast for smart contract developers. He previously co-founded SMARTeFunding, a platform for tokenizing bond ownership.', 'https://www.linkedin.com/in/sharif-elfouly-975146142', '', 'SMARTeFunding (Co-founder)', 'https://github.com/shafu0x', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('4a95f658-cf02-4324-bfd3-dcf146281bfe', '31c55d15-5647-49b9-ac6d-7d88a348e66b', 'Jeff Yan (Jeffrey Yan)', 'Co-founder & CEO', 'Jeff Yan is a physics prodigy who earned a silver medal at the 2012 International Physics Olympiad in Estonia and a gold medal at the 2013 IPhO in Denmark, representing the United States. He graduated from Harvard in 2017 with an AB/SM in Mathematics and Computer Science, then joined Hudson River Trading as an algorithm developer, gaining expertise in ultra-low-latency trading. After a brief stint at Google, he founded Chameleon Trading in early 2020, which grew into one of the largest crypto market-making firms. Following the collapse of FTX in November 2022, Yan pivoted to building Hyperliquid, bootstrapping it entirely from Chameleon Trading profits and deliberately rejecting all VC funding to maintain credible neutrality. With a team of 11 people based primarily in Singapore, he built a platform commanding dominant DEX perpetuals market share, earning recognition in CoinDesk''s Most Influential 2025 list and Decrypt''s 2025 Project of the Year.', '', 'https://x.com/chameleon_jeff', 'Hudson River Trading (Algorithm Developer), Google (Brief stint), Chameleon Trading (Founder)', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('1aadf934-77f8-4333-88a1-ef2aa82ed565', '31c55d15-5647-49b9-ac6d-7d88a348e66b', 'iliensinc', 'Co-founder', 'Iliensinc is the pseudonymous co-founder of Hyperliquid and a Harvard classmate of Jeff Yan. While maintaining anonymity, iliensinc has been instrumental in building Hyperliquid''s high-performance L1 blockchain from the ground up. Iliensinc is active in community communications—notably clarifying on Discord that Hyperliquid has never conducted external financing and detailing token unlock mechanics.', '', 'https://x.com/iliensinc', '', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('e54b7ce9-e1bf-459c-b3b3-d98b53708de3', 'e91b75de-72c6-4d0d-b445-9d5a3b3c7694', 'Noah Tweedale', 'Co-founder & CEO', 'Noah Tweedale serves as CEO of Baton Corporation Ltd, the UK-registered company that develops and operates Pump.fun. He is one of three entrepreneurs who launched what became one of the fastest-growing crypto applications in history. Tweedale has maintained a low public profile, citing security concerns given the massive crypto assets the platform manages.', '', '', 'Baton Corporation (CEO)', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('a8c0a743-42fd-46e3-aa23-d73b248be5f7', 'e91b75de-72c6-4d0d-b445-9d5a3b3c7694', 'Alon Cohen', 'Co-founder & COO', 'Alon Cohen is the most public-facing co-founder of Pump.fun, serving as COO of Baton Corporation. Known initially by his pseudonym ''Alon,'' he publicly stated his intention to create ''the most fun place on the internet'' when launching the platform in January 2024. Cohen has been the primary spokesperson for the platform''s strategic direction, including the launch of PumpSwap DEX and the vision for cross-chain trading infrastructure. He has spearheaded Pump.fun''s aggressive expansion strategy, including the Padre and Vyper acquisitions.', '', 'https://x.com/a1lon9', '', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('d4364918-9a44-44f0-9c62-b0e0884e4015', 'e91b75de-72c6-4d0d-b445-9d5a3b3c7694', 'Dylan Kerler', 'Co-founder & CTO', 'Dylan Kerler leads Pump.fun''s development team, responsible for writing the platform''s code and iterating features. He is the most technically oriented of the three co-founders and has an extremely minimal public presence, operating primarily under the alias @outdoteth on X. A WIRED investigation linked Kerler to 2017 cryptocurrency projects eBitcoinCash and EthereumCash that were flagged by blockchain security firm CertiK as potential rug pulls, which he allegedly launched as a teenager.', '', 'https://x.com/outdoteth', '', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('e8a33d7f-27de-4dda-bcbf-7930f9b7adc1', '668114ed-2300-4608-9634-324a80cba4b6', 'Guy Young', 'Founder & CEO', 'Guy Young brings nearly a decade of traditional finance experience spanning investment banking, hedge funds, and private equity to Ethena. He spent six years at Cerberus Capital Management, a firm with over $50 billion in AUM, where he served as Head of Principal Investments at a Cerberus affiliate and led the firm''s expansion into Australian markets, overseeing strategic investments across banking, specialty finance, insurance, and fintech. He founded Ethena in 2023, inspired by Arthur Hayes'' ''Dust on Crust'' thesis, and scaled it into one of the largest stablecoin protocols in crypto. Named to CoinDesk''s Most Influential 2025 list, Young is credited with sparking a new ''yieldcoin'' asset category at the intersection of DeFi rails and TradFi basis trades, and is recognized for his pragmatic approach to decentralization that prioritizes practical trade-offs over ideological purity.', 'https://www.linkedin.com/in/guy-young-a11914279/', 'https://twitter.com/leptokurtic_', 'Cerberus Capital Management (Head of Principal Investments)', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('bff2567b-c1a7-45db-957e-810205176a8a', '668114ed-2300-4608-9634-324a80cba4b6', 'Conor Ryder', 'Head of Research', 'Conor Ryder is a CFA Charterholder who serves as Head of Research and Data at Ethena Labs, joining as one of its earliest team members in July 2023. Before Ethena, he was a Research Analyst at Kaiko, a leading crypto market data provider, from April 2022 to July 2023. Prior to entering crypto, he held roles at Mercer and StepStone Group in traditional finance. He holds a Bachelor''s degree in Business and Law from University College Dublin. Ryder has become a prominent public voice for Ethena, with insights featured in CNBC, Bloomberg, Financial Times, Reuters, and CoinDesk.', 'https://www.linkedin.com/in/conor-ryder-cfa-82261b112/', 'https://twitter.com/ConorRyder', 'Kaiko (Research Analyst), Mercer, StepStone Group', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('e976f47b-ce9e-4a6b-9ef0-96091baeefa7', '668114ed-2300-4608-9634-324a80cba4b6', 'Zach Rosenberg', 'General Counsel', 'Zach Rosenberg serves as General Counsel at Ethena Labs, overseeing the protocol''s legal and regulatory strategy. Prior to Ethena, he operated Rosehill Legal, a boutique law firm servicing early-stage startups and venture funds, after almost a decade at PwC in its M&A Tax practice. He holds an LLM in Taxation from Georgetown University Law Center.', 'https://www.linkedin.com/in/zach-rosenberg-31470313/', '', 'Rosehill Legal, PwC (M&A Tax)', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('d690a060-20ea-4233-8111-0948ca7f639b', '668114ed-2300-4608-9634-324a80cba4b6', 'Brian Grosso', 'Head of Engineering', '', '', '', '', '', '') ON CONFLICT DO NOTHING;
INSERT INTO public.founders (id, company_id, name, role, bio, linkedin_url, twitter_url, prior_companies, github_url, personal_url) VALUES ('a40fffbb-1915-44fd-900c-657aa6c2a76b', '668114ed-2300-4608-9634-324a80cba4b6', 'Elliot Parker', 'COO', 'Elliot Parker serves in a senior operational and product role at Ethena Labs. Prior to Ethena, he was a product manager at Paradigm.', 'https://www.linkedin.com/in/elliot-parker-3454a4167/', '', 'Paradigm (Product Manager)', '', '') ON CONFLICT DO NOTHING;
